// ============ LOGO BASE64 ============
// PEGA TU BASE64 AQUÍ ABAJO (reemplaza PEGAR_BASE64_AQUI con tu string)
const LOGO_BASE64 = "data:image/png;base64,"

function formatDate(ts: number): string {
  return new Date(ts).toLocaleDateString('es-PR', { year: 'numeric', month: 'long', day: 'numeric' })
}

function formatDateShort(ts: number): string {
  return new Date(ts).toLocaleDateString('es-PR', { year: 'numeric', month: 'short', day: 'numeric' })
}

function formatCurrency(n: number): string {
  return '$' + n.toFixed(2).replace(/\B(?=(\d{3})+(?!\d))/g, ',')
}

function getPaymentLabel(method?: string): string {
  if (!method) return 'N/A'
  const labels: Record<string, string> = {
    cash: 'Efectivo', ath_movil: 'ATH Móvil', capital_one: 'Capital One',
    chase_visa: 'Chase Visa', paypal: 'PayPal', check: 'Cheque',
    sams_mastercard: "Sam's MC", transfer: 'Transferencia',
    ach: 'ACH', credit_card: 'Tarjeta Crédito', zelle: 'Zelle'
  }
  return labels[method] || method
}

function getCategoryLabel(cat: string): string {
  const labels: Record<string, string> = {
    before: '📷 ANTES',
    after: '✅ DESPUÉS',
    diagnostic: '🔍 DIAGNÓSTICO',
    equipment: '⚙️ EQUIPO',
    area: '📐 ÁREA',
    receipt: '🧾 RECIBO',
    other: '📎 OTROS'
  }
  return labels[cat] || cat.toUpperCase()
}

export function generateInvoiceNumber(type: 'invoice' | 'quote'): string {
  const prefix = type === 'invoice' ? 'CS-INV' : 'CS-COT'
  const d = new Date()
  const yr = d.getFullYear().toString().slice(-2)
  const mo = String(d.getMonth() + 1).padStart(2, '0')
  const rand = String(Math.floor(Math.random() * 9000) + 1000)
  return `${prefix}-${yr}${mo}-${rand}`
}

// ============ INVOICE PDF - ESTILO ANTHROPIC (MULTI-PAGE) ============
export function generateInvoicePDF(invoice: Invoice): Blob {
  // Recalculate deposit fields defensively in case stored values are stale
  if (invoice.deposit_enabled && invoice.deposit_type && invoice.deposit_value != null) {
    const depositAmount = invoice.deposit_type === 'percentage'
      ? invoice.total * (invoice.deposit_value / 100)
      : invoice.deposit_value
    invoice = { ...invoice, deposit_amount: depositAmount, balance_due: invoice.total - depositAmount }
  }

  const doc = new jsPDF()
  const pageW = doc.internal.pageSize.getWidth()
  const pageH = doc.internal.pageSize.getHeight()
  const isQuote = invoice.type === 'quote'
  const title = isQuote ? 'Quote' : 'Invoice'
  const marginL = 20
  const marginR = 20
  const FOOTER_ZONE = 30
  let MAX_Y = pageH - FOOTER_ZONE

  // === HELPERS ===
  function addFooter() {
    doc.setDrawColor(220, 220, 220)
    doc.setLineWidth(0.3)
    doc.line(marginL, pageH - 22, pageW - marginR, pageH - 22)
    doc.setFontSize(9)
    doc.setTextColor(0, 150, 150)
    doc.setFont('helvetica', 'italic')
    doc.text(COMPANY_SLOGAN, pageW / 2, pageH - 14, { align: 'center' })
    doc.setFont('helvetica', 'normal')
  }

  function checkPageBreak(neededSpace: number, currentY: number): number {
    if (currentY + neededSpace > MAX_Y) {
      addFooter()
      doc.addPage()
      return 20
    }
    return currentY
  }

  function drawTableHeaders(startY: number): number {
    let ty = startY
    doc.setDrawColor(220, 220, 220)
    doc.setLineWidth(0.3)
    doc.line(marginL, ty, pageW - marginR, ty)
    ty += 6
    doc.setFontSize(9)
    doc.setTextColor(80, 80, 80)
    doc.setFont('helvetica', 'normal')
    doc.text('Description', marginL, ty)
    doc.text('Qty', pageW - marginR - 55, ty, { align: 'right' })
    doc.text('Unit price', pageW - marginR - 25, ty, { align: 'right' })
    doc.text('Amount', pageW - marginR, ty, { align: 'right' })
    ty += 3
    doc.line(marginL, ty, pageW - marginR, ty)
    ty += 7
    return ty
  }

  // === TITLE ===
  doc.setFontSize(32)
  doc.setTextColor(30, 30, 30)
  doc.text(title, marginL, 28)

  // === LOGO ===
  try {
  doc.addImage(LOGO_BASE64, 'PNG', 120, 16, 74, 31)
  } catch { }

  // === INVOICE META ===
  let y = 40
  doc.setFontSize(10)
  doc.setTextColor(30, 30, 30)

  doc.setFont('helvetica', 'bold')
  doc.text('Invoice number', marginL, y)
  doc.setFont('helvetica', 'normal')
  doc.text(invoice.invoice_number, marginL + 35, y)

  if (invoice.service_date) {
    y += 6
    doc.setFont('helvetica', 'bold')
    doc.text('Service date', marginL, y)
    doc.setFont('helvetica', 'normal')
    doc.text(formatDate(invoice.service_date), marginL + 35, y)
  }

  // === COMPANY INFO & BILL TO ===
  y = 68
  const colRight = 110

  doc.setFontSize(10)
  doc.setFont('helvetica', 'bold')
  doc.setTextColor(30, 30, 30)
  doc.text(COMPANY_NAME, marginL, y)
  doc.setFont('helvetica', 'normal')
  doc.setTextColor(60, 60, 60)
  doc.text(COMPANY_ADDRESS, marginL, y + 5)
  doc.text(COMPANY_CITY, marginL, y + 10)
  doc.text(COMPANY_PHONE, marginL, y + 15)
  doc.text(COMPANY_EMAIL, marginL, y + 20)

  doc.setFont('helvetica', 'bold')
  doc.setTextColor(30, 30, 30)
  doc.text('Bill to', colRight, y)
  doc.setFont('helvetica', 'normal')
  doc.setTextColor(60, 60, 60)
  let billY = y + 5
  doc.text(invoice.client_name, colRight, billY)
  if (invoice.location_name) { billY += 5; doc.text(invoice.location_name, colRight, billY) }
  if (invoice.client_address) { billY += 5; doc.text(invoice.client_address, colRight, billY) }
  if (invoice.client_phone) { billY += 5; doc.text(invoice.client_phone, colRight, billY) }
  if (invoice.client_email) { billY += 5; doc.text(invoice.client_email, colRight, billY) }

  // === COMPACT CHECK: dry-run to see if content fits on one page ===
  {
    const DRY_THRESHOLD = 21 // mm (~80px at 96dpi)
    const dry = new jsPDF()
    dry.setFontSize(10)
    const dryMaxDescWidth = pageW - marginL - marginR - 70
    let dryY = 105 + 10 // table start + headers
    invoice.items.forEach(item => {
      const lines = dry.splitTextToSize(item.description, dryMaxDescWidth)
      dryY += Math.max(7, lines.length * 4.5 + 3)
    })
    if (invoice.notes) {
      dry.setFontSize(9)
      const nl = dry.splitTextToSize(invoice.notes, pageW - marginL - marginR)
      dryY += 10 + nl.length * 4
    }
    dryY += 55 // totals + paid stamp estimate
    const overflow = dryY - MAX_Y
    if (overflow > 0 && overflow <= DRY_THRESHOLD) {
      MAX_Y = pageH - FOOTER_ZONE + 12 // reclaim 12mm footer margin
    }
  }

  // === ITEMS TABLE ===
  y = 105
  y = drawTableHeaders(y)

  const descFontSize = MAX_Y > pageH - FOOTER_ZONE ? 8 : 10
  const lineHeight = MAX_Y > pageH - FOOTER_ZONE ? 4.0 : 4.5
  invoice.items.forEach((item) => {
    const maxDescWidth = pageW - marginL - marginR - 70
    doc.setFontSize(descFontSize)
    const descLines = doc.splitTextToSize(item.description, maxDescWidth)
    const rowHeight = Math.max(7, descLines.length * lineHeight + 3)

    y = checkPageBreak(rowHeight, y)
    if (y === 20) {
      y = drawTableHeaders(y)
    }

    doc.setFontSize(descFontSize)
    doc.setTextColor(30, 30, 30)
    doc.setFont('helvetica', 'normal')
    doc.text(descLines, marginL, y)
    doc.setFontSize(10)
    doc.text(String(item.quantity), pageW - marginR - 55, y, { align: 'right' })
    doc.text(formatCurrency(item.unit_price), pageW - marginR - 25, y, { align: 'right' })
    doc.text(formatCurrency(item.total), pageW - marginR, y, { align: 'right' })
    y += rowHeight
  })

  // === NOTES (antes de totales, con label) ===
  if (invoice.notes) {
    y += 10
    y = checkPageBreak(10, y)
    doc.setFontSize(9)
    doc.setTextColor(0, 130, 130)
    doc.setFont('helvetica', 'bold')
    doc.text('Nota:', marginL, y)
    doc.setFont('helvetica', 'normal')
    doc.setTextColor(80, 80, 80)
    y += 5
    const noteLines = doc.splitTextToSize(invoice.notes, pageW - marginL - marginR)
    for (let i = 0; i < noteLines.length; i++) {
      y = checkPageBreak(5, y)
      doc.text(noteLines[i], marginL, y)
      y += 4
    }
  }

  // === TOTALS ===
  y = checkPageBreak(40, y)
  y += 10
  const labelX = pageW - marginR - 60
  const valueX = pageW - marginR

  doc.setFontSize(10)
  doc.setTextColor(60, 60, 60)
  doc.setFont('helvetica', 'normal')

  doc.text('Subtotal', labelX, y)
  doc.text(formatCurrency(invoice.subtotal), valueX, y, { align: 'right' })

  if (invoice.tax_rate > 0) {
    y += 6
    doc.text(`Tax (${invoice.tax_rate}%)`, labelX, y)
    doc.text(formatCurrency(invoice.tax_amount), valueX, y, { align: 'right' })
  }

  y += 6
  doc.text('Total', labelX, y)
  doc.text(formatCurrency(invoice.total), valueX, y, { align: 'right' })

  if (invoice.deposit_enabled && invoice.deposit_amount) {
    y += 8
    doc.setDrawColor(200, 170, 50)
    doc.setLineWidth(0.3)
    doc.line(labelX, y - 2, valueX, y - 2)
    y += 2
    doc.setTextColor(180, 140, 20)
    doc.text(`Depósito (${invoice.deposit_type === 'percentage' ? invoice.deposit_value + '%' : 'fijo'})`, labelX, y)
    doc.text(`-${formatCurrency(invoice.deposit_amount)}`, valueX, y, { align: 'right' })
    y += 8
    doc.setDrawColor(200, 170, 50)
    doc.line(labelX, y - 2, valueX, y - 2)
    y += 2
    doc.setFont('helvetica', 'bold')
    doc.setFontSize(12)
    doc.setTextColor(220, 120, 20)
    doc.text('BALANCE PENDIENTE', labelX - 10, y)
    doc.text(`${formatCurrency(invoice.balance_due || 0)} USD`, valueX, y, { align: 'right' })
    doc.setFont('helvetica', 'normal')
    doc.setFontSize(10)
  } else {
    y += 6
    doc.setFont('helvetica', 'bold')
    doc.setTextColor(30, 30, 30)
    doc.text('Amount due', labelX, y)
    doc.text(`${formatCurrency(invoice.total)} USD`, valueX, y, { align: 'right' })
    doc.setFont('helvetica', 'normal')
  }

  // Retención Hacienda
  if (invoice.retention_percent && invoice.retention_percent > 0) {
    const retAmt = invoice.retention_amount ?? (invoice.total * invoice.retention_percent / 100)
    const netAmt = invoice.total - retAmt
    y += 10
    y = checkPageBreak(20, y)
    doc.setDrawColor(220, 170, 0)
    doc.setLineWidth(0.2)
    doc.line(labelX, y - 2, valueX, y - 2)
    doc.setFontSize(9)
    doc.setTextColor(160, 120, 0)
    doc.text(`Retención Hacienda (${invoice.retention_percent}%)`, labelX, y)
    doc.text(`-${formatCurrency(retAmt)}`, valueX, y, { align: 'right' })
    y += 7
    doc.setFont('helvetica', 'bold')
    doc.setFontSize(11)
    doc.setTextColor(34, 120, 34)
    doc.text('NETO A RECIBIR', labelX, y)
    doc.text(`${formatCurrency(netAmt)} USD`, valueX, y, { align: 'right' })
    doc.setFont('helvetica', 'normal')
    doc.setFontSize(10)
  }


  // === PAID STAMP ===
  if (invoice.status === 'paid' && invoice.paid_date) {
    y += 15
    y = checkPageBreak(10, y)
    doc.setFontSize(10)
    doc.setTextColor(34, 197, 94)
    doc.setFont('helvetica', 'bold')
    doc.text(`✓ PAID - ${formatDate(invoice.paid_date)} (${getPaymentLabel(invoice.paid_method)})`, marginL, y)
    doc.setFont('helvetica', 'normal')
  }

  // === FOOTER + PAGE NUMBERS EN TODAS LAS PÁGINAS ===
  const totalPages = doc.getNumberOfPages()
  for (let i = 1; i <= totalPages; i++) {
    doc.setPage(i)
    addFooter()
    doc.setFontSize(8)
    doc.setTextColor(120, 120, 120)
    doc.setFont('helvetica', 'normal')
    doc.text(`Page ${i} of ${totalPages}`, pageW - marginR, pageH - 6, { align: 'right' })
  }

  return doc.output('blob')
}

export function downloadInvoicePDF(invoice: Invoice) {
  const blob = generateInvoicePDF(invoice)
  const url = URL.createObjectURL(blob)
  const a = document.createElement('a')
  const prefix = invoice.type === 'quote' ? 'Quote' : 'Invoice'
  a.href = url
  a.download = `${prefix}-${invoice.invoice_number}.pdf`
  a.click()
  URL.revokeObjectURL(url)
}

// ============ CATEGORY REPORT ============
export function generateCategoryReport(
  events: EventRecord[],
  category: string,
  startDate: number,
  endDate: number
) {
  const filtered = events.filter(e =>
    e.timestamp >= startDate &&
    e.timestamp <= endDate &&
    (category === 'general' || category === 'gastos' || category === 'ingresos' || category === 'personales' || category === 'vehículos' || e.category?.toLowerCase() === category.toLowerCase())
  )

  const doc = new jsPDF()
  doc.setFontSize(16)
  doc.setTextColor(0, 150, 150)
  doc.text(`${COMPANY_NAME} - Reporte ${category}`, 14, 15)
  doc.setFontSize(10)
  doc.setTextColor(80, 80, 80)
  doc.text(`${formatDate(startDate)} - ${formatDate(endDate)}`, 14, 22)

  if (filtered.length === 0) {
    doc.text('No hay registros para este período.', 14, 35)
  } else {
    autoTable(doc, {
      startY: 30,
      head: [['Fecha', 'Tipo', 'Categoría', 'Monto', 'Detalle', 'Método']],
      body: filtered.map(e => [
        formatDateShort(e.timestamp),
        e.type === 'income' ? 'Ingreso' : 'Gasto',
        e.category || '-',
        formatCurrency(e.amount),
        e.vendor || e.client || e.note || '-',
        getPaymentLabel(e.payment_method)
      ]),
      headStyles: { fillColor: [0, 150, 150], textColor: [255, 255, 255] },
      bodyStyles: { fontSize: 8 }
    })

    const finalY = (doc as any).lastAutoTable.finalY + 10
    const totalIncome = filtered.filter(e => e.type === 'income').reduce((s, e) => s + e.amount, 0)
    const totalExpense = filtered.filter(e => e.type === 'expense').reduce((s, e) => s + e.amount, 0)
    
    doc.setFontSize(10)
    doc.text(`Total Ingresos: ${formatCurrency(totalIncome)}`, 14, finalY)
    doc.text(`Total Gastos: ${formatCurrency(totalExpense)}`, 14, finalY + 6)
    doc.setFont('helvetica', 'bold')
    doc.text(`Neto: ${formatCurrency(totalIncome - totalExpense)}`, 14, finalY + 12)
  }

  doc.save(`Reporte-${category}-${new Date().toISOString().split('T')[0]}.pdf`)
}

// ============ P&L REPORT ============
export function generatePLReport(
  events: EventRecord[],
  startDate: number,
  endDate: number,
  periodLabel: string
) {
  const filtered = events.filter(e => 
    e.timestamp >= startDate && 
    e.timestamp <= endDate &&
    e.expense_type !== 'personal'
  )

  const income = filtered.filter(e => e.type === 'income')
  const expenses = filtered.filter(e => e.type === 'expense')
  const totalIncome = income.reduce((s, e) => s + e.amount, 0)
  const totalExpense = expenses.reduce((s, e) => s + e.amount, 0)
  const profit = totalIncome - totalExpense

  const expenseByCategory: Record<string, number> = {}
  expenses.forEach(e => {
    const cat = e.category || 'Otros'
    expenseByCategory[cat] = (expenseByCategory[cat] || 0) + e.amount
  })

  const incomeByCategory: Record<string, number> = {}
  income.forEach(e => {
    const cat = e.category || 'Otros'
    incomeByCategory[cat] = (incomeByCategory[cat] || 0) + e.amount
  })

  const doc = new jsPDF()
  doc.setFontSize(18)
  doc.setTextColor(0, 150, 150)
  doc.text(`${COMPANY_NAME}`, 14, 15)
  doc.setFontSize(14)
  doc.setTextColor(40, 40, 40)
  doc.text(`Estado de Pérdidas y Ganancias - ${periodLabel}`, 14, 24)
  doc.setFontSize(9)
  doc.setTextColor(100, 100, 100)
  doc.text(`${formatDate(startDate)} - ${formatDate(endDate)}`, 14, 30)

  let y = 42

  doc.setFontSize(11)
  doc.setTextColor(34, 197, 94)
  doc.setFont('helvetica', 'bold')
  doc.text('INGRESOS', 14, y)
  doc.setFont('helvetica', 'normal')
  y += 7

  doc.setFontSize(9)
  doc.setTextColor(60, 60, 60)
  Object.entries(incomeByCategory).sort((a, b) => b[1] - a[1]).forEach(([cat, total]) => {
    doc.text(cat, 20, y)
    doc.text(formatCurrency(total), 100, y, { align: 'right' })
    y += 5
  })
  
  y += 3
  doc.setFont('helvetica', 'bold')
  doc.setTextColor(34, 197, 94)
  doc.text('Total Ingresos', 20, y)
  doc.text(formatCurrency(totalIncome), 100, y, { align: 'right' })
  doc.setFont('helvetica', 'normal')

  y += 12
  doc.setFontSize(11)
  doc.setTextColor(239, 68, 68)
  doc.setFont('helvetica', 'bold')
  doc.text('GASTOS', 14, y)
  doc.setFont('helvetica', 'normal')
  y += 7

  doc.setFontSize(9)
  doc.setTextColor(60, 60, 60)
  Object.entries(expenseByCategory).sort((a, b) => b[1] - a[1]).forEach(([cat, total]) => {
    doc.text(cat, 20, y)
    doc.text(formatCurrency(total), 100, y, { align: 'right' })
    y += 5
  })

  y += 3
  doc.setFont('helvetica', 'bold')
  doc.setTextColor(239, 68, 68)
  doc.text('Total Gastos', 20, y)
  doc.text(formatCurrency(totalExpense), 100, y, { align: 'right' })
  doc.setFont('helvetica', 'normal')

  y += 12
  doc.setDrawColor(200, 200, 200)
  doc.line(14, y - 3, 110, y - 3)
  
  doc.setFontSize(12)
  doc.setFont('helvetica', 'bold')
  const profitColor = profit >= 0 ? [34, 197, 94] : [239, 68, 68]
  doc.setTextColor(profitColor[0], profitColor[1], profitColor[2])
  doc.text(profit >= 0 ? 'GANANCIA NETA' : 'PÉRDIDA NETA', 14, y)
  doc.text(formatCurrency(Math.abs(profit)), 100, y, { align: 'right' })

  if (totalIncome > 0) {
    y += 8
    doc.setFontSize(9)
    doc.setTextColor(100, 100, 100)
    const margin = ((profit / totalIncome) * 100).toFixed(1)
    doc.text(`Margen: ${margin}%`, 14, y)
  }

  doc.save(`P&L-${periodLabel.replace(/\s+/g, '-')}-${new Date().toISOString().split('T')[0]}.pdf`)
}

// ============ AR REPORT ============
export function generateARReport(invoices: Invoice[]) {
  const pending = invoices.filter(inv => 
    inv.type === 'invoice' && 
    (inv.status === 'sent' || inv.status === 'overdue' || inv.status === 'draft')
  )

  const doc = new jsPDF()
  doc.setFontSize(16)
  doc.setTextColor(0, 150, 150)
  doc.text(`${COMPANY_NAME} - Cuentas por Cobrar`, 14, 15)
  doc.setFontSize(10)
  doc.setTextColor(80, 80, 80)
  doc.text(`Generado: ${formatDate(Date.now())}`, 14, 22)

  if (pending.length === 0) {
    doc.setFontSize(12)
    doc.text('🎉 No hay facturas pendientes', 14, 40)
  } else {
    const total = pending.reduce((s, inv) => s + inv.total, 0)
    
    doc.setFontSize(14)
    doc.setTextColor(239, 68, 68)
    doc.text(`Total Pendiente: ${formatCurrency(total)}`, 14, 32)

    autoTable(doc, {
      startY: 40,
      head: [['#', 'Cliente', 'Fecha', 'Vence', 'Status', 'Total']],
      body: pending.map(inv => [
        inv.invoice_number,
        inv.client_name,
        formatDateShort(inv.issue_date),
        inv.due_date ? formatDateShort(inv.due_date) : '-',
        inv.status === 'overdue' ? 'VENCIDA' : inv.status === 'sent' ? 'Enviada' : 'Borrador',
        formatCurrency(inv.total)
      ]),
      headStyles: { fillColor: [0, 150, 150] },
      bodyStyles: { fontSize: 9 },
      columnStyles: { 4: { cellWidth: 25, fontStyle: 'bold' } },
      didParseCell: (data) => {
        if (data.column.index === 4 && data.cell.raw === 'VENCIDA') {
          data.cell.styles.textColor = [239, 68, 68]
        }
      }
    })
  }

  doc.save(`Cuentas-por-Cobrar-${new Date().toISOString().split('T')[0]}.pdf`)
}

// ============ PAYMENT METHOD REPORT ============
export function generatePaymentMethodReport(
  events: EventRecord[],
  paymentMethod: string,
  startDate: number,
  endDate: number
) {
  const filtered = events.filter(e =>
    e.timestamp >= startDate &&
    e.timestamp <= endDate &&
    e.payment_method?.toLowerCase().includes(paymentMethod.replace(/_/g, ' ').toLowerCase())
  )

  const doc = new jsPDF()
  doc.setFontSize(16)
  doc.setTextColor(0, 150, 150)
  doc.text(`${COMPANY_NAME} - Reporte ${getPaymentLabel(paymentMethod)}`, 14, 15)
  doc.setFontSize(10)
  doc.setTextColor(80, 80, 80)
  doc.text(`${formatDate(startDate)} - ${formatDate(endDate)}`, 14, 22)

  if (filtered.length === 0) {
    doc.text('No hay registros para este método de pago.', 14, 35)
  } else {
    const catSummary: Record<string, number> = {}
    filtered.forEach(e => {
      const cat = e.category || 'Otros'
      catSummary[cat] = (catSummary[cat] || 0) + e.amount
    })

    autoTable(doc, {
      startY: 30,
      head: [['Fecha', 'Categoría', 'Monto', 'Detalle']],
      body: filtered.map(e => [
        formatDateShort(e.timestamp),
        e.category || '-',
        formatCurrency(e.amount),
        e.vendor || e.note || '-'
      ]),
      foot: [['TOTAL', '', formatCurrency(filtered.reduce((s, e) => s + e.amount, 0)), '']]
    })

    const finalY = (doc as any).lastAutoTable.finalY + 10
    doc.setFontSize(11)
    doc.text('Por categoría:', 14, finalY)
    let catY = finalY + 7
    doc.setFontSize(9)
    Object.entries(catSummary).sort((a, b) => b[1] - a[1]).forEach(([cat, total]) => {
      doc.text(`${cat}: ${formatCurrency(total)}`, 20, catY)
      catY += 5
    })
  }

  doc.save(`${paymentMethod}-${new Date().toISOString().split('T')[0]}.pdf`)
}

// ============ PHOTO REPORT ============
export function generatePhotoReport(
  photos: ClientPhoto[],
  clientName: string,
  jobDescription?: string
) {
  if (photos.length === 0) {
    alert('No hay fotos para este reporte')
    return
  }

  const doc = new jsPDF()
  const pageW = doc.internal.pageSize.getWidth()
  const pageH = doc.internal.pageSize.getHeight()
  const marginL = 15
  const marginR = 15

  const photosByDate: Record<string, ClientPhoto[]> = {}
  photos.forEach(photo => {
    const dateKey = new Date(photo.timestamp).toLocaleDateString('es-PR')
    if (!photosByDate[dateKey]) photosByDate[dateKey] = []
    photosByDate[dateKey].push(photo)
  })

  const sortedDates = Object.keys(photosByDate).sort((a, b) => {
    const dateA = new Date(photosByDate[a][0].timestamp)
    const dateB = new Date(photosByDate[b][0].timestamp)
    return dateB.getTime() - dateA.getTime()
  })

  const addHeader = (_pageNum: number) => {
    try {
   doc.addImage(LOGO_BASE64, 'PNG', pageW - marginR - 40, 10, 40, 17)
    } catch { }
    doc.setFontSize(14); doc.setTextColor(0, 150, 150); doc.setFont('helvetica', 'bold')
    doc.text(COMPANY_NAME, marginL, 18); doc.setFont('helvetica', 'normal')
    doc.setFontSize(9); doc.setTextColor(80, 80, 80)
    doc.text(COMPANY_ADDRESS, marginL, 24); doc.text(COMPANY_CITY, marginL, 28)
    doc.text(`Tel: ${COMPANY_PHONE}`, marginL, 32)
    doc.setDrawColor(0, 150, 150); doc.setLineWidth(0.5); doc.line(marginL, 38, pageW - marginR, 38)
    doc.setFontSize(12); doc.setTextColor(30, 30, 30); doc.setFont('helvetica', 'bold')
    doc.text(`Reporte de Fotos - ${clientName}`, marginL, 48); doc.setFont('helvetica', 'normal')
    if (jobDescription) { doc.setFontSize(10); doc.setTextColor(60, 60, 60); doc.text(jobDescription, marginL, 54) }
    doc.setFontSize(9); doc.setTextColor(100, 100, 100)
    doc.text(`Generado: ${formatDate(Date.now())}`, marginL, jobDescription ? 60 : 54)
    doc.text(`Total: ${photos.length} foto(s)`, marginL + 80, jobDescription ? 60 : 54)
  }

  const addPhotoFooter = (pageNum: number, _totalPages: number) => {
    doc.setDrawColor(200, 200, 200); doc.setLineWidth(0.3)
    doc.line(marginL, pageH - 18, pageW - marginR, pageH - 18)
    doc.setFontSize(8); doc.setTextColor(150, 150, 150)
    doc.text(COMPANY_SLOGAN, pageW / 2, pageH - 12, { align: 'center' })
    doc.text(`${COMPANY_PHONE} | ${COMPANY_EMAIL}`, pageW / 2, pageH - 7, { align: 'center' })
    doc.text(`Página ${pageNum}`, pageW - marginR, pageH - 7, { align: 'right' })
  }

  let currentPage = 1
  addHeader(currentPage)
  let y = 70
  const imgWidth = 170
  const imgHeight = 130

  sortedDates.forEach((dateKey) => {
    const datePhotos = photosByDate[dateKey]
    if (y > pageH - 100) {
      addPhotoFooter(currentPage, sortedDates.length); doc.addPage(); currentPage++; addHeader(currentPage); y = 70
    }
    doc.setFontSize(11); doc.setTextColor(0, 150, 150); doc.setFont('helvetica', 'bold')
    doc.text(`📅 ${formatDate(datePhotos[0].timestamp)}`, marginL, y); doc.setFont('helvetica', 'normal')
    doc.setDrawColor(200, 200, 200); doc.setLineWidth(0.2); doc.line(marginL, y + 2, pageW - marginR, y + 2)
    y += 10

    const categories = ['before', 'after', 'diagnostic', 'equipment', 'area', 'other']
    categories.forEach(cat => {
      const catPhotos = datePhotos.filter(p => p.category === cat)
      if (catPhotos.length === 0) return
      if (y > pageH - 90) {
        addPhotoFooter(currentPage, sortedDates.length); doc.addPage(); currentPage++; addHeader(currentPage); y = 70
      }
      doc.setFontSize(10); doc.setTextColor(60, 60, 60); doc.setFont('helvetica', 'bold')
      doc.text(getCategoryLabel(cat), marginL + 5, y); doc.setFont('helvetica', 'normal'); y += 6

      catPhotos.forEach((photo) => {
        if (y > pageH - 160) {
          addPhotoFooter(currentPage, sortedDates.length); doc.addPage(); currentPage++; addHeader(currentPage); y = 70
        }
        const imgX = (pageW - imgWidth) / 2
        try {
          doc.addImage(photo.photo_data, imgX, y, imgWidth, imgHeight)
          doc.setDrawColor(220, 220, 220); doc.setLineWidth(0.3); doc.rect(imgX, y, imgWidth, imgHeight)
        } catch {
          doc.setDrawColor(200, 200, 200); doc.rect(imgX, y, imgWidth, imgHeight)
          doc.setFontSize(10); doc.setTextColor(150, 150, 150); doc.text('Imagen no disponible', imgX + 50, y + 65)
        }
        let descY = y + imgHeight + 4
        if (photo.description) {
          doc.setFontSize(9); doc.setTextColor(40, 40, 40)
          const descLines = doc.splitTextToSize(photo.description, imgWidth)
          doc.text(descLines.slice(0, 2), imgX, descY); descY += descLines.slice(0, 2).length * 4
        }
        if (photo.equipment_type || photo.location) {
          doc.setFontSize(8); doc.setTextColor(100, 100, 100)
          const info = [photo.equipment_type, photo.location].filter(Boolean).join(' | ')
          doc.text(info, imgX, descY + 3)
        }
        y += imgHeight + 25
      })
      y += 5
    })
    y += 8
  })

  addPhotoFooter(currentPage, currentPage)
  const safeName = clientName.replace(/[^a-zA-Z0-9]/g, '-')
  doc.save(`Fotos-${safeName}-${new Date().toISOString().split('T')[0]}.pdf`)
}

// ============ CLIENT LIST PDF ============
