// ============ PAYROLL / NÓMINA REPORT ============
export function generatePayrollReport(
  events: EventRecord[],
  employees: Employee[],
  startDate: number,
  endDate: number,
  periodLabel: string
) {
  const payrollEvents = events.filter(e =>
    e.timestamp >= startDate && e.timestamp <= endDate &&
    e.type === 'expense' && e.employee_id != null
  )

  const doc = new jsPDF()
  const pageW = doc.internal.pageSize.getWidth()
  const pageH = doc.internal.pageSize.getHeight()
  const marginL = 20
  const marginR = 20

  try { doc.addImage(LOGO_BASE64, 'PNG', pageW - marginR - 40, 10, 40, 17) } catch { }

  doc.setFontSize(18); doc.setTextColor(0, 150, 150); doc.text(COMPANY_NAME, marginL, 18)
  doc.setFontSize(14); doc.setTextColor(40, 40, 40); doc.text(`Reporte de Nómina - ${periodLabel}`, marginL, 28)
  doc.setFontSize(9); doc.setTextColor(100, 100, 100)
  doc.text(`${formatDate(startDate)} - ${formatDate(endDate)}`, marginL, 34)
  doc.text(`Generado: ${formatDate(Date.now())}`, marginL, 39)

  const byEmployee: Record<number, { name: string; events: EventRecord[]; total: number }> = {}
  payrollEvents.forEach(e => {
    const empId = e.employee_id!
    if (!byEmployee[empId]) {
      const emp = employees.find(em => em.id === empId)
      byEmployee[empId] = { name: emp ? `${emp.first_name} ${emp.last_name}`.trim() : `Empleado #${empId}`, events: [], total: 0 }
    }
    byEmployee[empId].events.push(e)
    byEmployee[empId].total += e.amount
  })

  const grandTotal = payrollEvents.reduce((s, e) => s + e.amount, 0)

  doc.setFontSize(11); doc.setTextColor(30, 30, 30); doc.setFont('helvetica', 'bold')
  doc.text('Resumen por Empleado', marginL, 50); doc.setFont('helvetica', 'normal')

  const summaryRows = Object.values(byEmployee)
    .sort((a, b) => b.total - a.total)
    .map(emp => [emp.name, String(emp.events.length), formatCurrency(emp.total)])

  autoTable(doc, {
    startY: 55,
    head: [['Empleado', '# Pagos', 'Total']],
    body: summaryRows,
    foot: [['TOTAL', String(payrollEvents.length), formatCurrency(grandTotal)]],
    headStyles: { fillColor: [0, 150, 150], textColor: [255, 255, 255] },
    footStyles: { fillColor: [240, 240, 240], fontStyle: 'bold', textColor: [30, 30, 30] },
    bodyStyles: { fontSize: 9 }
  })

  let detailY = (doc as any).lastAutoTable.finalY + 15

  Object.values(byEmployee).sort((a, b) => b.total - a.total).forEach(emp => {
    if (detailY > pageH - 60) { doc.addPage(); detailY = 20 }
    doc.setFontSize(10); doc.setTextColor(0, 150, 150); doc.setFont('helvetica', 'bold')
    doc.text(emp.name, marginL, detailY); doc.setFont('helvetica', 'normal')
    autoTable(doc, {
      startY: detailY + 3,
      head: [['Fecha', 'Monto', 'Método', 'Nota']],
      body: emp.events.map(e => [
        formatDateShort(e.timestamp), formatCurrency(e.amount),
        getPaymentLabel(e.payment_method), e.note || '-'
      ]),
      headStyles: { fillColor: [60, 60, 60], textColor: [255, 255, 255], fontSize: 8 },
      bodyStyles: { fontSize: 8 }, margin: { left: marginL + 5 }
    })
    detailY = (doc as any).lastAutoTable.finalY + 12
  })

  const totalPages = doc.getNumberOfPages()
  for (let i = 1; i <= totalPages; i++) {
    doc.setPage(i); doc.setDrawColor(200, 200, 200); doc.setLineWidth(0.3)
    doc.line(marginL, pageH - 15, pageW - marginR, pageH - 15)
    doc.setFontSize(8); doc.setTextColor(150, 150, 150)
    doc.text(COMPANY_SLOGAN, pageW / 2, pageH - 8, { align: 'center' })
    doc.text(`Página ${i} de ${totalPages}`, pageW - marginR, pageH - 8, { align: 'right' })
  }

  doc.save(`Nomina-${periodLabel.replace(/\s+/g, '-')}-${new Date().toISOString().split('T')[0]}.pdf`)
}

// ============ EXPENSES WITH RECEIPT PHOTOS REPORT ============

export function generateExpenseReceiptsReport(
  events: EventRecord[],
  startDate: number,
  endDate: number,
  periodLabel: string,
  clientFilter?: string
) {
  let filtered = events.filter(e =>
    e.timestamp >= startDate && e.timestamp <= endDate &&
    e.type === 'expense'
  )

  if (clientFilter && clientFilter !== 'all') {
    filtered = filtered.filter(e => e.client === clientFilter)
  }

  const doc = new jsPDF()
  const pageW = doc.internal.pageSize.getWidth()
  const pageH = doc.internal.pageSize.getHeight()
  const marginL = 15
  const marginR = 15

  try { doc.addImage(LOGO_BASE64, 'PNG', pageW - marginR - 40, 10, 40, 17) } catch { }

  doc.setFontSize(16); doc.setTextColor(0, 150, 150); doc.text(COMPANY_NAME, marginL, 18)
  const title = clientFilter && clientFilter !== 'all'
    ? `Gastos — ${clientFilter} — ${periodLabel}`
    : `Gastos — ${periodLabel}`
  doc.setFontSize(12); doc.setTextColor(40, 40, 40); doc.text(title, marginL, 27)
  doc.setFontSize(9); doc.setTextColor(100, 100, 100)
  doc.text(`${formatDate(startDate)} — ${formatDate(endDate)}`, marginL, 33)

  const totalAmount = filtered.reduce((s, e) => s + e.amount, 0)
  const withPhotos = filtered.filter(e => (e.receipt_photos && e.receipt_photos.length > 0) || e.photo)

  doc.text(`Total gastos: ${filtered.length} | Con recibo: ${withPhotos.length}`, marginL, 38)
  doc.setFont('helvetica', 'bold')
  doc.setFontSize(11); doc.setTextColor(220, 50, 50)
  doc.text(`Total: ${formatCurrency(totalAmount)}`, marginL, 44)
  doc.setFont('helvetica', 'normal')

  // === RESUMEN POR CATEGORÍA ===
  let y = 52
  const byCat: Record<string, { total: number; count: number }> = {}
  filtered.forEach(e => {
    const cat = e.category || 'Sin categoría'
    if (!byCat[cat]) byCat[cat] = { total: 0, count: 0 }
    byCat[cat].total += e.amount
    byCat[cat].count++
  })

  autoTable(doc, {
    startY: y,
    head: [['Categoría', '# Gastos', 'Total']],
    body: Object.entries(byCat)
      .sort((a, b) => b[1].total - a[1].total)
      .map(([cat, data]) => [cat, String(data.count), formatCurrency(data.total)]),
    headStyles: { fillColor: [0, 150, 150], textColor: [255, 255, 255], fontSize: 9 },
    bodyStyles: { fontSize: 9 },
    columnStyles: { 2: { halign: 'right' as const } }
  })

  y = (doc as any).lastAutoTable.finalY + 10

  // === RESUMEN POR CLIENTE ===
  if (!clientFilter || clientFilter === 'all') {
    const byClient: Record<string, { total: number; count: number }> = {}
    filtered.forEach(e => {
      const cl = e.client || 'General'
      if (!byClient[cl]) byClient[cl] = { total: 0, count: 0 }
      byClient[cl].total += e.amount
      byClient[cl].count++
    })

    if (Object.keys(byClient).length > 1) {
      autoTable(doc, {
        startY: y,
        head: [['Cliente', '# Gastos', 'Total']],
        body: Object.entries(byClient)
          .sort((a, b) => b[1].total - a[1].total)
          .map(([cl, data]) => [cl, String(data.count), formatCurrency(data.total)]),
        headStyles: { fillColor: [60, 60, 60], textColor: [255, 255, 255], fontSize: 9 },
        bodyStyles: { fontSize: 9 },
        columnStyles: { 2: { halign: 'right' as const } }
      })
      y = (doc as any).lastAutoTable.finalY + 10
    }
  }

  // === RESUMEN POR MES ===
  const byMonth: Record<string, { total: number; count: number }> = {}
  filtered.forEach(e => {
    const d = new Date(e.timestamp)
    const key = d.toLocaleDateString('es-PR', { year: 'numeric', month: 'long' })
    if (!byMonth[key]) byMonth[key] = { total: 0, count: 0 }
    byMonth[key].total += e.amount
    byMonth[key].count++
  })

  if (Object.keys(byMonth).length > 1) {
    if (y > pageH - 60) { doc.addPage(); y = 20 }
    autoTable(doc, {
      startY: y,
      head: [['Mes', '# Gastos', 'Total']],
      body: Object.entries(byMonth).map(([month, data]) => [
        month, String(data.count), formatCurrency(data.total)
      ]),
      headStyles: { fillColor: [100, 100, 100], textColor: [255, 255, 255], fontSize: 9 },
      bodyStyles: { fontSize: 9 },
      columnStyles: { 2: { halign: 'right' as const } }
    })
    y = (doc as any).lastAutoTable.finalY + 10
  }

  // === MÉTODO DE PAGO ===
  const byMethod: Record<string, { total: number; count: number }> = {}
  filtered.forEach(e => {
    const method = getPaymentLabel(e.payment_method) || 'Sin método'
    if (!byMethod[method]) byMethod[method] = { total: 0, count: 0 }
    byMethod[method].total += e.amount
    byMethod[method].count++
  })

  if (y > pageH - 60) { doc.addPage(); y = 20 }
  autoTable(doc, {
    startY: y,
    head: [['Método de Pago', '# Gastos', 'Total']],
    body: Object.entries(byMethod)
      .sort((a, b) => b[1].total - a[1].total)
      .map(([method, data]) => [method, String(data.count), formatCurrency(data.total)]),
    headStyles: { fillColor: [80, 80, 150], textColor: [255, 255, 255], fontSize: 9 },
    bodyStyles: { fontSize: 9 },
    columnStyles: { 2: { halign: 'right' as const } }
  })

  y = (doc as any).lastAutoTable.finalY + 10

  // === DETALLE DE CADA GASTO ===
  if (y > pageH - 60) { doc.addPage(); y = 20 }
  doc.setFontSize(11); doc.setTextColor(0, 150, 150); doc.setFont('helvetica', 'bold')
  doc.text('DETALLE DE GASTOS', marginL, y)
  doc.setFont('helvetica', 'normal')
  y += 5

  autoTable(doc, {
    startY: y,
    head: [['Fecha', 'Categoría', 'Vendor/Cliente', 'Método', 'Monto', 'Nota']],
    body: filtered.sort((a, b) => b.timestamp - a.timestamp).map(e => [
      formatDateShort(e.timestamp),
      e.category || '-',
      e.vendor || e.client || '-',
      getPaymentLabel(e.payment_method),
      formatCurrency(e.amount),
      (e.note || '-').substring(0, 40)
    ]),
    headStyles: { fillColor: [0, 150, 150], textColor: [255, 255, 255], fontSize: 8 },
    bodyStyles: { fontSize: 8 },
    columnStyles: {
      0: { cellWidth: 22 },
      4: { halign: 'right' as const, cellWidth: 22 },
      5: { cellWidth: 40 }
    }
  })

  y = (doc as any).lastAutoTable.finalY + 15

  // === FOTOS DE RECIBOS ===
  if (withPhotos.length > 0) {
    if (y > pageH - 40) { doc.addPage(); y = 20 }
    doc.setFontSize(11); doc.setTextColor(0, 150, 150); doc.setFont('helvetica', 'bold')
    doc.text('FOTOS DE RECIBOS', marginL, y)
    doc.setFont('helvetica', 'normal')
    y += 8

    withPhotos.sort((a, b) => b.timestamp - a.timestamp).forEach((event, idx) => {
      if (y > pageH - 130) { doc.addPage(); y = 20 }

      const contentW = pageW - marginL - marginR
      doc.setDrawColor(0, 150, 150); doc.setLineWidth(0.3)
      doc.setFillColor(248, 248, 248); doc.roundedRect(marginL, y, contentW, 22, 2, 2, 'FD')

      doc.setFontSize(10); doc.setTextColor(30, 30, 30); doc.setFont('helvetica', 'bold')
      doc.text(`#${idx + 1} — ${formatDateShort(event.timestamp)}`, marginL + 4, y + 6)
      doc.setFont('helvetica', 'normal')

      doc.setFontSize(9)
      doc.text(`${formatCurrency(event.amount)}`, marginL + 4, y + 12)
      doc.text(`${event.category || '-'}`, marginL + 40, y + 12)
      doc.text(`${getPaymentLabel(event.payment_method)}`, marginL + 80, y + 12)
      doc.text(`${event.vendor || event.client || '-'}`, marginL + 4, y + 18)

      if (event.expense_type === 'personal') {
        doc.setTextColor(168, 85, 247); doc.text('PERSONAL', pageW - marginR - 25, y + 6)
      }
      y += 26

      const eventPhotos: string[] = []
      if (event.receipt_photos && event.receipt_photos.length > 0) eventPhotos.push(...event.receipt_photos)
      else if (event.photo) eventPhotos.push(event.photo)

      eventPhotos.forEach((photoData) => {
        if (y > pageH - 120) { doc.addPage(); y = 20 }
        const imgW = 160, imgH = 100, imgX = (pageW - imgW) / 2
        try {
          const imgSrc = photoData.startsWith('data:') ? photoData : `data:image/jpeg;base64,${photoData}`
          doc.addImage(imgSrc, imgX, y, imgW, imgH)
          doc.setDrawColor(220, 220, 220); doc.setLineWidth(0.2); doc.rect(imgX, y, imgW, imgH)
        } catch {
          doc.setDrawColor(200, 200, 200); doc.rect(imgX, y, imgW, imgH)
          doc.setFontSize(9); doc.setTextColor(150, 150, 150); doc.text('Imagen no disponible', imgX + 50, y + 50)
        }
        y += imgH + 8
      })
      y += 10
    })
  }

  // === FOOTERS ===
  const totalPages = doc.getNumberOfPages()
  for (let i = 1; i <= totalPages; i++) {
    doc.setPage(i)
    doc.setDrawColor(200, 200, 200); doc.setLineWidth(0.3)
    doc.line(marginL, pageH - 15, pageW - marginR, pageH - 15)
    doc.setFontSize(8); doc.setTextColor(150, 150, 150)
    doc.text(COMPANY_SLOGAN, pageW / 2, pageH - 8, { align: 'center' })
    doc.text(`Página ${i} de ${totalPages}`, pageW - marginR, pageH - 8, { align: 'right' })
  }

  const suffix = clientFilter && clientFilter !== 'all' ? `-${clientFilter.replace(/\s+/g, '-')}` : ''
  doc.save(`Gastos${suffix}-${periodLabel.replace(/\s+/g, '-')}-${new Date().toISOString().split('T')[0]}.pdf`)
}

// ============ ACCOUNTANT REPORT (multi-page) ============
export function generateAccountantReport(
  events: EventRecord[],
  invoices: Invoice[],
  employees: Employee[],
  bankTxs: any[],
  bankAccounts: any[],
  startDate: number,
  endDate: number,
  periodLabel: string
) {
  const doc = new jsPDF()
  const pageW = doc.internal.pageSize.getWidth()
  const pageH = doc.internal.pageSize.getHeight()
  const mL = 14, mR = 14

  // Guard: if y is too close to bottom, add page and reset
  const chk = (y: number, reserve = 45): number => {
    if (y > pageH - reserve) { doc.addPage(); return 20 }
    return y
  }

  // Draw a section header bar + title, return new y
  const sec = (title: string, y: number, r: number, g: number, b: number): number => {
    doc.setDrawColor(r, g, b); doc.setLineWidth(0.6); doc.line(mL, y, pageW - mR, y); y += 7
    doc.setFontSize(13); doc.setTextColor(r, g, b); doc.setFont('helvetica', 'bold')
    doc.text(title, mL, y); doc.setFont('helvetica', 'normal')
    return y + 8
  }

  const addFooter = () => {
    const total = doc.getNumberOfPages()
    for (let i = 1; i <= total; i++) {
      doc.setPage(i)
      doc.setDrawColor(200, 200, 200); doc.setLineWidth(0.3)
      doc.line(mL, pageH - 14, pageW - mR, pageH - 14)
      doc.setFontSize(8); doc.setTextColor(150, 150, 150)
      doc.text(COMPANY_SLOGAN, pageW / 2, pageH - 7, { align: 'center' })
      doc.text(`Pág ${i} de ${total}`, pageW - mR, pageH - 7, { align: 'right' })
    }
  }

  // ── DATA PREPARATION ────────────────────────────────────────────────
  const incomeEvents = events
    .filter(e => e.type === 'income' && e.timestamp >= startDate && e.timestamp <= endDate)
    .sort((a, b) => a.timestamp - b.timestamp)

  const allExpenses = events
    .filter(e => e.type === 'expense' && e.timestamp >= startDate && e.timestamp <= endDate)
    .sort((a, b) => a.timestamp - b.timestamp)

  const bizExpenses    = allExpenses.filter(e => e.expense_type !== 'personal')
  const personalExpenses = allExpenses.filter(e => e.expense_type === 'personal')
  const payrollEvents  = bizExpenses.filter(e => e.employee_id != null)
  const nonPayrollBiz  = bizExpenses.filter(e => e.employee_id == null)

  // Invoices: paid_date / payment_date for period classification
  const periodInvoices = invoices.filter(inv => {
    if (inv.type !== 'invoice') return false
    const ts = inv.paid_date || inv.payment_date || inv.created_at
    return ts >= startDate && ts <= endDate
  })
  const pendingInvoices = invoices.filter(inv =>
    inv.type === 'invoice' && (inv.status === 'sent' || inv.status === 'overdue')
  )

  const totalIncome    = incomeEvents.reduce((s, e) => s + e.amount, 0)
  const totalRetention = incomeEvents.reduce((s, e) => s + (e.retention_amount || 0), 0)
  const totalBizExp    = nonPayrollBiz.reduce((s, e) => s + e.amount, 0)
  const totalPayroll   = payrollEvents.reduce((s, e) => s + e.amount, 0)
  const totalPersonal  = personalExpenses.reduce((s, e) => s + e.amount, 0)
  const taxCollected   = periodInvoices.reduce((s, i) => s + (i.tax_amount || 0), 0)
  const invRetention   = periodInvoices.reduce((s, i) => s + (i.retention_amount || 0), 0)
  const effectiveRetention = Math.max(totalRetention, invRetention)
  const profit         = totalIncome - totalBizExp - totalPayroll
  const arTotal        = pendingInvoices.reduce((s, i) => s + i.total, 0)
  const periodBankTxs  = bankTxs.filter(t => t.date >= startDate && t.date <= endDate)

  // Helper: group events by YYYY-MM
  const groupByMonth = (evts: EventRecord[]): Record<string, EventRecord[]> => {
    const map: Record<string, EventRecord[]> = {}
    evts.forEach(e => {
      const key = new Date(e.timestamp).toISOString().slice(0, 7)
      if (!map[key]) map[key] = []
      map[key].push(e)
    })
    return map
  }

  const monthLabel = (isoKey: string) =>
    new Date(isoKey + '-15').toLocaleDateString('es-PR', { year: 'numeric', month: 'long' })

  const statusLabel = (s: string) =>
    s === 'paid' ? 'Pagada' : s === 'overdue' ? 'Vencida' : s === 'sent' ? 'Enviada' : s === 'cancelled' ? 'Cancelada' : 'Borrador'

  // ── SECCIÓN 1: PORTADA ───────────────────────────────────────────────
  try { doc.addImage(LOGO_BASE64, 'PNG', pageW - mR - 45, 8, 45, 20) } catch {}
  doc.setFontSize(22); doc.setTextColor(0, 130, 130); doc.setFont('helvetica', 'bold')
  doc.text(COMPANY_NAME, mL, 22); doc.setFont('helvetica', 'normal')
  doc.setFontSize(16); doc.setTextColor(40, 40, 40)
  doc.text(`Reporte Contable — ${periodLabel}`, mL, 33)
  doc.setFontSize(10); doc.setTextColor(100, 100, 100)
  doc.text(`Período: ${formatDate(startDate)} — ${formatDate(endDate)}`, mL, 41)
  doc.text(`Generado: ${formatDate(Date.now())}`, mL, 47)

  let y = 56
  doc.setDrawColor(0, 130, 130); doc.setLineWidth(0.8); doc.line(mL, y, pageW - mR, y); y += 8
  doc.setFontSize(12); doc.setTextColor(30, 30, 30); doc.setFont('helvetica', 'bold')
  doc.text('RESUMEN EJECUTIVO', mL, y); doc.setFont('helvetica', 'normal'); y += 4

  autoTable(doc, {
    startY: y,
    body: [
      ['Ingresos Brutos del Período',            formatCurrency(totalIncome),              ''],
      ['Gastos de Negocio (sin nómina)',          formatCurrency(totalBizExp),              ''],
      ['Nómina / Empleados',                      formatCurrency(totalPayroll),             ''],
      ['GANANCIA / PÉRDIDA NETA',                 formatCurrency(profit),                  profit >= 0 ? '✓' : '⚠'],
      ['Margen Neto',                             totalIncome > 0 ? ((profit / totalIncome) * 100).toFixed(1) + '%' : 'N/A', ''],
      ['IVU Cobrado (a remitir a Hacienda)',       formatCurrency(taxCollected),             'Form SC 2915'],
      ['Retención de Contratistas (estimada)',    formatCurrency(effectiveRetention),       'Form 480 / 499R'],
      ['Gastos Personales (no deducibles)',       formatCurrency(totalPersonal),            ''],
      ['Cuentas por Cobrar Pendientes',           formatCurrency(arTotal),                 `${pendingInvoices.length} facturas`],
    ],
    styles: { fontSize: 10, cellPadding: 3 },
    columnStyles: {
      0: { cellWidth: 102, textColor: [60, 60, 60] as [number,number,number] },
      1: { cellWidth: 42, halign: 'right' as const, fontStyle: 'bold' as const },
      2: { cellWidth: 36, textColor: [120, 120, 120] as [number,number,number], fontSize: 8 },
    },
    didParseCell: (data: any) => {
      if (data.section !== 'body') return
      const row = data.row.raw as string[]
      if (row[0] === 'GANANCIA / PÉRDIDA NETA') {
        data.cell.styles.textColor = profit >= 0 ? [34, 140, 34] : [200, 50, 50]
        data.cell.styles.fontStyle = 'bold'
        if (data.column.index === 1) data.cell.styles.fontSize = 12
      }
      if (row[0] === 'Ingresos Brutos del Período' && data.column.index === 1)
        data.cell.styles.textColor = [34, 140, 34]
      if ((row[0] === 'Gastos de Negocio (sin nómina)' || row[0] === 'Nómina / Empleados') && data.column.index === 1)
        data.cell.styles.textColor = [200, 50, 50]
    }
  })
  y = (doc as any).lastAutoTable.finalY + 10

  // Table of contents
  y = chk(y, 60)
  doc.setFontSize(10); doc.setTextColor(80, 80, 80); doc.setFont('helvetica', 'bold')
  doc.text('CONTENIDO', mL, y); doc.setFont('helvetica', 'normal'); y += 5
  doc.setFontSize(9); doc.setTextColor(100, 100, 100)
  ;[
    '1. Ingresos Detallados',
    '2. Facturas del Período',
    '3. Cuentas por Cobrar',
    '4. Gastos Detallados',
    '5. Nómina / Empleados',
    ...(periodBankTxs.length > 0 ? ['6. Conciliación Bancaria'] : []),
    `${periodBankTxs.length > 0 ? '7' : '6'}. Resumen Final y Obligaciones Fiscales`,
  ].forEach(item => { doc.text(item, mL + 5, y); y += 5 })

  // ── SECCIÓN 2: INGRESOS DETALLADOS ──────────────────────────────────
  doc.addPage(); y = 20
  y = sec('1. INGRESOS DETALLADOS', y, 34, 140, 94)

  if (incomeEvents.length === 0) {
    doc.setFontSize(9); doc.setTextColor(100, 100, 100)
    doc.text('No hay ingresos registrados en este período.', mL + 5, y); y += 10
  } else {
    // Build invoice lookup: client_name (lower) + total → invoice_number
    const invLookup = new Map<string, string>()
    periodInvoices.forEach(inv => {
      invLookup.set(`${inv.client_name.toLowerCase().trim()}-${inv.total}`, inv.invoice_number)
    })

    Object.entries(groupByMonth(incomeEvents)).sort().forEach(([key, evts]) => {
      const ml = monthLabel(key)
      const mTotal = evts.reduce((s, e) => s + e.amount, 0)
      const mRet   = evts.reduce((s, e) => s + (e.retention_amount || 0), 0)
      y = chk(y, 50)
      doc.setFontSize(9); doc.setTextColor(34, 100, 60); doc.setFont('helvetica', 'bold')
      doc.text(ml, mL, y); doc.setFont('helvetica', 'normal'); y += 3

      autoTable(doc, {
        startY: y,
        head: [['Fecha', 'Cliente', 'Descripción', 'Método Cobro', 'Factura #', 'Retención', 'Monto']],
        body: evts.map(e => {
          const invNum = invLookup.get(`${(e.client || '').toLowerCase().trim()}-${e.amount}`) || '-'
          return [
            formatDateShort(e.timestamp),
            (e.client || '-').slice(0, 22),
            (e.note || e.category || '-').slice(0, 28),
            getPaymentLabel(e.payment_method),
            invNum,
            e.retention_amount ? formatCurrency(e.retention_amount) : '-',
            formatCurrency(e.amount),
          ]
        }),
        foot: [['', '', '', '', `Total ${ml}:`, mRet > 0 ? formatCurrency(mRet) : '', formatCurrency(mTotal)]],
        headStyles: { fillColor: [34, 140, 94], textColor: [255, 255, 255], fontSize: 7 },
        bodyStyles: { fontSize: 8 },
        footStyles: { fillColor: [220, 245, 225], textColor: [20, 80, 40], fontSize: 8, fontStyle: 'bold' },
        columnStyles: {
          0: { cellWidth: 18 },
          1: { cellWidth: 38 },
          2: { cellWidth: 44 },
          3: { cellWidth: 28 },
          4: { cellWidth: 20 },
          5: { halign: 'right' as const, cellWidth: 20 },
          6: { halign: 'right' as const, cellWidth: 22 },
        },
      })
      y = (doc as any).lastAutoTable.finalY + 8
    })

    // Totals
    y = chk(y, 30)
    doc.setFontSize(9); doc.setFont('helvetica', 'bold')
    doc.setTextColor(34, 140, 94)
    doc.text('Total Ingresos Brutos:', 110, y)
    doc.text(formatCurrency(totalIncome), pageW - mR, y, { align: 'right' }); y += 6
    if (totalRetention > 0) {
      doc.setTextColor(200, 50, 50)
      doc.text('(-) Retención Hacienda:', 110, y)
      doc.text(formatCurrency(totalRetention), pageW - mR, y, { align: 'right' }); y += 6
      doc.setTextColor(30, 30, 30)
      doc.text('= Total Neto Recibido:', 110, y)
      doc.text(formatCurrency(totalIncome - totalRetention), pageW - mR, y, { align: 'right' }); y += 6
    }
    doc.setFont('helvetica', 'normal')
  }

  // ── SECCIÓN 3: FACTURAS ──────────────────────────────────────────────
  doc.addPage(); y = 20
  y = sec('2. FACTURAS DEL PERÍODO', y, 0, 100, 160)

  if (periodInvoices.length === 0) {
    doc.setFontSize(9); doc.setTextColor(100, 100, 100)
    doc.text('No hay facturas en este período.', mL + 5, y); y += 10
  } else {
    const sorted = [...periodInvoices].sort((a, b) => {
      const ta = a.paid_date || a.payment_date || a.created_at
      const tb = b.paid_date || b.payment_date || b.created_at
      return ta - tb
    })
    autoTable(doc, {
      startY: y,
      head: [['#', 'F.Creación', 'F.Pago', 'Cliente', 'Localidad', 'Subtotal', 'IVU', 'Total', 'Retención', 'Neto', 'Status']],
      body: sorted.map(inv => {
        const paidTs = inv.paid_date || inv.payment_date
        const neto = inv.total - (inv.retention_amount || 0)
        return [
          inv.invoice_number,
          formatDateShort(inv.created_at),
          paidTs ? formatDateShort(paidTs) : '-',
          inv.client_name.slice(0, 16),
          (inv.location_name || '-').slice(0, 14),
          formatCurrency(inv.subtotal),
          formatCurrency(inv.tax_amount || 0),
          formatCurrency(inv.total),
          inv.retention_amount ? formatCurrency(inv.retention_amount) : '-',
          formatCurrency(neto),
          statusLabel(inv.status),
        ]
      }),
      headStyles: { fillColor: [0, 100, 160], textColor: [255, 255, 255], fontSize: 7 },
      bodyStyles: { fontSize: 7 },
      columnStyles: {
        0: { cellWidth: 17 },
        1: { cellWidth: 17 },
        2: { cellWidth: 17 },
        3: { cellWidth: 26 },
        4: { cellWidth: 20 },
        5: { halign: 'right' as const, cellWidth: 18 },
        6: { halign: 'right' as const, cellWidth: 14 },
        7: { halign: 'right' as const, cellWidth: 18 },
        8: { halign: 'right' as const, cellWidth: 18 },
        9: { halign: 'right' as const, cellWidth: 18 },
        10: { cellWidth: 14 },
      },
      didParseCell: (data: any) => {
        if (data.section === 'body' && data.column.index === 10) {
          const s = data.cell.raw as string
          if (s === 'Pagada') data.cell.styles.textColor = [34, 150, 34]
          else if (s === 'Vencida') data.cell.styles.textColor = [200, 50, 50]
          else data.cell.styles.textColor = [180, 140, 0]
        }
      },
    })
    y = (doc as any).lastAutoTable.finalY + 6

    const invTotal  = periodInvoices.reduce((s, i) => s + i.total, 0)
    const invTax    = periodInvoices.reduce((s, i) => s + (i.tax_amount || 0), 0)
    const invRet2   = periodInvoices.reduce((s, i) => s + (i.retention_amount || 0), 0)
    y = chk(y, 20)
    doc.setFontSize(9); doc.setFont('helvetica', 'bold'); doc.setTextColor(30, 30, 30)
    doc.text(`Total Facturado: ${formatCurrency(invTotal)}`, mL, y)
    doc.text(`IVU Total: ${formatCurrency(invTax)}`, mL + 65, y)
    if (invRet2 > 0) doc.text(`Retención Total: ${formatCurrency(invRet2)}`, mL + 115, y)
    doc.setFont('helvetica', 'normal'); y += 10
  }

  // ── SECCIÓN 4: CUENTAS POR COBRAR ────────────────────────────────────
  y = chk(y, 70)
  y = sec('3. CUENTAS POR COBRAR AL CIERRE', y, 180, 80, 0)

  if (pendingInvoices.length === 0) {
    doc.setFontSize(9); doc.setTextColor(34, 150, 34)
    doc.text('✓ No hay facturas pendientes de cobro.', mL + 5, y); y += 10
  } else {
    const now = Date.now()
    autoTable(doc, {
      startY: y,
      head: [['#', 'Cliente', 'F.Emisión', 'Vencimiento', 'Días Vencidos', 'Total', 'Status']],
      body: [...pendingInvoices]
        .sort((a, b) => (a.due_date || a.created_at) - (b.due_date || b.created_at))
        .map(inv => {
          const dueTs = inv.due_date || inv.created_at
          const days = Math.floor((now - dueTs) / 86400000)
          return [
            inv.invoice_number,
            inv.client_name.slice(0, 24),
            formatDateShort(inv.created_at),
            inv.due_date ? formatDateShort(inv.due_date) : '-',
            days > 0 ? `${days} días` : 'Vigente',
            formatCurrency(inv.total),
            inv.status === 'overdue' ? 'Vencida' : 'Enviada',
          ]
        }),
      headStyles: { fillColor: [180, 80, 0], textColor: [255, 255, 255], fontSize: 8 },
      bodyStyles: { fontSize: 8 },
      columnStyles: {
        4: { halign: 'center' as const },
        5: { halign: 'right' as const },
      },
      didParseCell: (data: any) => {
        if (data.section !== 'body') return
        if (data.column.index === 6 && data.cell.raw === 'Vencida') data.cell.styles.textColor = [200, 50, 50]
        if (data.column.index === 4 && (data.cell.raw as string) !== 'Vigente') data.cell.styles.textColor = [200, 50, 50]
      },
    })
    y = (doc as any).lastAutoTable.finalY + 5
    doc.setFontSize(10); doc.setFont('helvetica', 'bold'); doc.setTextColor(180, 80, 0)
    doc.text(`Total por Cobrar: ${formatCurrency(arTotal)}`, mL, y)
    doc.setFont('helvetica', 'normal'); y += 10
  }

  // ── SECCIÓN 5: GASTOS DETALLADOS ─────────────────────────────────────
  doc.addPage(); y = 20
  y = sec('4. GASTOS DETALLADOS', y, 160, 50, 50)

  // ─ Gastos de negocio por mes ─
  if (nonPayrollBiz.length > 0) {
    doc.setFontSize(9); doc.setTextColor(100, 100, 100)
    doc.text('Gastos de Negocio (deducibles)', mL, y); y += 4

    Object.entries(groupByMonth(nonPayrollBiz)).sort().forEach(([key, evts]) => {
      const ml = monthLabel(key)
      const mTotal = evts.reduce((s, e) => s + e.amount, 0)
      y = chk(y, 50)
      doc.setFontSize(8); doc.setTextColor(130, 40, 40); doc.setFont('helvetica', 'bold')
      doc.text(ml, mL, y); doc.setFont('helvetica', 'normal'); y += 3

      autoTable(doc, {
        startY: y,
        head: [['Fecha', 'Vendor / Descripción', 'Categoría', 'Método / Cuenta', 'Monto', 'Ded.']],
        body: evts.map(e => [
          formatDateShort(e.timestamp),
          (e.vendor || e.note || '-').slice(0, 32),
          e.category || '-',
          getPaymentLabel(e.payment_method),
          formatCurrency(e.amount),
          'Sí',
        ]),
        foot: [['', '', '', `Total ${ml}:`, formatCurrency(mTotal), '']],
        headStyles: { fillColor: [160, 50, 50], textColor: [255, 255, 255], fontSize: 7 },
        bodyStyles: { fontSize: 8 },
        footStyles: { fillColor: [245, 220, 220], textColor: [80, 30, 30], fontSize: 8, fontStyle: 'bold' },
        columnStyles: {
          0: { cellWidth: 18 },
          1: { cellWidth: 58 },
          2: { cellWidth: 36 },
          3: { cellWidth: 34 },
          4: { halign: 'right' as const, cellWidth: 22 },
          5: { cellWidth: 12, halign: 'center' as const },
        },
      })
      y = (doc as any).lastAutoTable.finalY + 6
    })

    // Summary by category
    y = chk(y, 60)
    const expByCat: Record<string, number> = {}
    nonPayrollBiz.forEach(e => { expByCat[e.category || 'Otros'] = (expByCat[e.category || 'Otros'] || 0) + e.amount })
    autoTable(doc, {
      startY: y,
      head: [['Resumen por Categoría', 'Total']],
      body: Object.entries(expByCat).sort((a, b) => b[1] - a[1]).map(([cat, total]) => [cat, formatCurrency(total)]),
      foot: [['TOTAL GASTOS NEGOCIO', formatCurrency(totalBizExp)]],
      headStyles: { fillColor: [100, 100, 100], textColor: [255, 255, 255], fontSize: 8 },
      bodyStyles: { fontSize: 8 },
      footStyles: { fillColor: [240, 240, 240], fontStyle: 'bold', fontSize: 9, textColor: [30, 30, 30] },
      columnStyles: { 1: { halign: 'right' as const } },
      tableWidth: 90,
    })
    y = (doc as any).lastAutoTable.finalY + 10
  }

  // ─ Gastos personales ─
  if (personalExpenses.length > 0) {
    y = chk(y, 60)
    doc.setFontSize(10); doc.setTextColor(150, 80, 0); doc.setFont('helvetica', 'bold')
    doc.text('Gastos Personales (NO deducibles)', mL, y); doc.setFont('helvetica', 'normal'); y += 4

    autoTable(doc, {
      startY: y,
      head: [['Fecha', 'Vendor / Descripción', 'Categoría', 'Método / Cuenta', 'Monto', 'Ded.']],
      body: personalExpenses.map(e => [
        formatDateShort(e.timestamp),
        (e.vendor || e.note || '-').slice(0, 32),
        e.category || '-',
        getPaymentLabel(e.payment_method),
        formatCurrency(e.amount),
        'No',
      ]),
      headStyles: { fillColor: [150, 80, 0], textColor: [255, 255, 255], fontSize: 7 },
      bodyStyles: { fontSize: 8 },
      columnStyles: {
        0: { cellWidth: 18 },
        1: { cellWidth: 58 },
        2: { cellWidth: 36 },
        3: { cellWidth: 34 },
        4: { halign: 'right' as const, cellWidth: 22 },
        5: { cellWidth: 12, halign: 'center' as const, textColor: [200, 50, 50] as [number,number,number] },
      },
    })
    y = (doc as any).lastAutoTable.finalY + 4
    doc.setFontSize(9); doc.setFont('helvetica', 'bold'); doc.setTextColor(150, 80, 0)
    doc.text(`Total Gastos Personales (no deducibles): ${formatCurrency(totalPersonal)}`, mL, y)
    doc.setFont('helvetica', 'normal'); y += 10
  }

  // ── SECCIÓN 6: NÓMINA ────────────────────────────────────────────────
  if (payrollEvents.length > 0) {
    doc.addPage(); y = 20
    y = sec('5. NÓMINA / PAGOS A EMPLEADOS', y, 60, 60, 140)

    const byEmp: Record<number, { name: string; retPct: number; events: EventRecord[]; total: number }> = {}
    payrollEvents.forEach(e => {
      const id = e.employee_id!
      if (!byEmp[id]) {
        const emp = employees.find(em => em.id === id)
        byEmp[id] = {
          name: emp ? `${emp.first_name} ${emp.last_name}`.trim() : `Empleado #${id}`,
          retPct: emp?.retention_percent || 0,
          events: [],
          total: 0,
        }
      }
      byEmp[id].events.push(e)
      byEmp[id].total += e.amount
    })

    autoTable(doc, {
      startY: y,
      head: [['Empleado', 'Clasificación', 'Retención %', '# Pagos', 'Total Bruto']],
      body: Object.values(byEmp).sort((a, b) => b.total - a.total).map(emp => [
        emp.name,
        emp.retPct > 0 ? 'Contratista (1099)' : 'Empleado (W-2)',
        emp.retPct > 0 ? `${emp.retPct}%` : '—',
        String(emp.events.length),
        formatCurrency(emp.total),
      ]),
      foot: [['TOTAL NÓMINA', '', '', String(payrollEvents.length), formatCurrency(totalPayroll)]],
      headStyles: { fillColor: [60, 60, 140], textColor: [255, 255, 255], fontSize: 9 },
      bodyStyles: { fontSize: 9 },
      footStyles: { fillColor: [240, 240, 240], fontStyle: 'bold', textColor: [30, 30, 30], fontSize: 9 },
      columnStyles: { 4: { halign: 'right' as const } },
    })
    y = (doc as any).lastAutoTable.finalY + 10

    Object.values(byEmp).sort((a, b) => b.total - a.total).forEach(emp => {
      y = chk(y, 50)
      doc.setFontSize(10); doc.setTextColor(60, 60, 140); doc.setFont('helvetica', 'bold')
      doc.text(`${emp.name}  —  ${emp.retPct > 0 ? 'Contratista' : 'Empleado'}`, mL, y)
      doc.setFont('helvetica', 'normal')
      autoTable(doc, {
        startY: y + 3,
        head: [['Fecha', 'Monto Bruto', 'Método', 'Retención', 'Nota']],
        body: [...emp.events].sort((a, b) => a.timestamp - b.timestamp).map(e => [
          formatDateShort(e.timestamp),
          formatCurrency(e.amount),
          getPaymentLabel(e.payment_method),
          emp.retPct > 0 ? formatCurrency(e.amount * emp.retPct / 100) : '—',
          e.note || '-',
        ]),
        headStyles: { fillColor: [80, 80, 110], textColor: [255, 255, 255], fontSize: 8 },
        bodyStyles: { fontSize: 8 },
        margin: { left: mL + 5 },
        columnStyles: {
          1: { halign: 'right' as const },
          3: { halign: 'right' as const, textColor: [200, 50, 50] as [number,number,number] },
        },
      })
      y = (doc as any).lastAutoTable.finalY + 10
    })
  }

  // ── SECCIÓN 7: CONCILIACIÓN BANCARIA ────────────────────────────────
  if (periodBankTxs.length > 0) {
    doc.addPage(); y = 20
    y = sec('6. CONCILIACIÓN BANCARIA', y, 0, 100, 130)

    const byAccount: Record<string, any[]> = {}
    periodBankTxs.forEach(t => {
      if (!byAccount[t.account_name]) byAccount[t.account_name] = []
      byAccount[t.account_name].push(t)
    })

    for (const [acctName, txList] of Object.entries(byAccount)) {
      const acct = bankAccounts.find((a: any) => a.payment_method_key === acctName || a.name === acctName)
      y = chk(y, 65)
      doc.setFontSize(11); doc.setTextColor(0, 100, 130); doc.setFont('helvetica', 'bold')
      doc.text(`🏦 ${acct?.name || acctName}`, mL, y); doc.setFont('helvetica', 'normal'); y += 4

      const matched  = txList.filter(t => t.match_status === 'matched').length
      const probable = txList.filter(t => t.match_status === 'probable').length
      const unmatched = txList.filter(t => t.match_status !== 'matched' && t.match_status !== 'probable').length
      const totalDebits  = txList.filter(t => t.direction === 'debit').reduce((s: number, t: any) => s + t.amount, 0)
      const totalCredits = txList.filter(t => t.direction === 'credit').reduce((s: number, t: any) => s + t.amount, 0)

      autoTable(doc, {
        startY: y,
        head: [['Transacciones', 'Conciliadas', 'Probables', 'Sin Match', 'Total Débitos', 'Total Créditos']],
        body: [[String(txList.length), String(matched), String(probable), String(unmatched), formatCurrency(totalDebits), formatCurrency(totalCredits)]],
        headStyles: { fillColor: [0, 100, 130], textColor: [255, 255, 255], fontSize: 8 },
        bodyStyles: { fontSize: 8 },
        columnStyles: { 4: { halign: 'right' as const }, 5: { halign: 'right' as const } },
      })
      y = (doc as any).lastAutoTable.finalY + 4

      autoTable(doc, {
        startY: y,
        head: [['Fecha', 'Descripción Banco', 'Monto Banco', 'Evento App', 'Monto App', 'Estado']],
        body: [...txList].sort((a: any, b: any) => a.date - b.date).map((tx: any) => {
          const ev = tx.match_event_id ? events.find(e => e.id === tx.match_event_id) : null
          return [
            formatDateShort(tx.date),
            tx.description.slice(0, 32),
            tx.direction === 'debit' ? `-${formatCurrency(tx.amount)}` : `+${formatCurrency(tx.amount)}`,
            ev ? (ev.vendor || ev.client || ev.category || '').slice(0, 22) : '—',
            ev ? (ev.type === 'expense' ? `-${formatCurrency(ev.amount)}` : `+${formatCurrency(ev.amount)}`) : '—',
            tx.match_status === 'matched' ? '✓ OK' : tx.match_status === 'probable' ? '? Probable' : '⚠ Sin match',
          ]
        }),
        headStyles: { fillColor: [40, 70, 100], textColor: [255, 255, 255], fontSize: 7 },
        bodyStyles: { fontSize: 7 },
        columnStyles: {
          0: { cellWidth: 18 },
          1: { cellWidth: 56 },
          2: { halign: 'right' as const, cellWidth: 24 },
          3: { cellWidth: 38 },
          4: { halign: 'right' as const, cellWidth: 24 },
          5: { cellWidth: 22 },
        },
        didParseCell: (data: any) => {
          if (data.section === 'body' && data.column.index === 5) {
            const s = data.cell.raw as string
            if (s.startsWith('✓')) data.cell.styles.textColor = [34, 150, 34]
            else if (s.startsWith('⚠')) data.cell.styles.textColor = [200, 50, 50]
            else data.cell.styles.textColor = [180, 140, 0]
          }
        },
      })
      y = (doc as any).lastAutoTable.finalY + 10
    }
  }

  // ── SECCIÓN 8: RESUMEN FINAL ─────────────────────────────────────────
  doc.addPage(); y = 20
  const finalSecNum = periodBankTxs.length > 0 ? '7' : '6'
  y = sec(`${finalSecNum}. RESUMEN FINAL`, y, 60, 60, 60)

  // Balance general
  autoTable(doc, {
    startY: y,
    head: [['BALANCE DEL PERÍODO', '']],
    body: [
      ['Ingresos Brutos',                  formatCurrency(totalIncome)],
      ['(-) Retención Hacienda (estimada)',`(${formatCurrency(effectiveRetention)})`],
      ['= Ingresos Netos Recibidos',        formatCurrency(totalIncome - effectiveRetention)],
      ['', ''],
      ['(-) Gastos Deducibles de Negocio', `(${formatCurrency(totalBizExp)})`],
      ['(-) Nómina / Empleados',           `(${formatCurrency(totalPayroll)})`],
      ['= GANANCIA / PÉRDIDA NETA',         formatCurrency(profit)],
    ].filter(r => r[0] !== ''),
    headStyles: { fillColor: [60, 60, 60], textColor: [255, 255, 255], fontSize: 10 },
    bodyStyles: { fontSize: 10 },
    columnStyles: { 1: { halign: 'right' as const, fontStyle: 'bold' as const } },
    didParseCell: (data: any) => {
      if (data.section !== 'body') return
      const row = data.row.raw as string[]
      if (row[0] === '= GANANCIA / PÉRDIDA NETA') {
        data.cell.styles.textColor = profit >= 0 ? [34, 140, 34] : [200, 50, 50]
        data.cell.styles.fontStyle = 'bold'
        data.cell.styles.fontSize = 11
      }
      if (row[0].startsWith('(-)') && data.column.index === 1) data.cell.styles.textColor = [200, 50, 50]
      if (row[0] === 'Ingresos Brutos' && data.column.index === 1) data.cell.styles.textColor = [34, 140, 34]
    },
  })
  y = (doc as any).lastAutoTable.finalY + 10

  // Obligaciones fiscales
  y = chk(y, 70)
  autoTable(doc, {
    startY: y,
    head: [['OBLIGACIONES FISCALES', 'Monto', 'Referencia']],
    body: [
      ['IVU Cobrado (a remitir a Hacienda)',        formatCurrency(taxCollected),        'Form SC 2915 / Planilla Mensual'],
      ['Retención de Contratistas (a reportar)',    formatCurrency(effectiveRetention),  'Form 480.6B / 499R-2'],
      ['Cuentas por Cobrar Pendientes al Cierre',  formatCurrency(arTotal),             `${pendingInvoices.length} facturas sin cobrar`],
    ],
    headStyles: { fillColor: [120, 40, 40], textColor: [255, 255, 255], fontSize: 9 },
    bodyStyles: { fontSize: 9 },
    columnStyles: {
      1: { halign: 'right' as const, textColor: [180, 40, 40] as [number,number,number], fontStyle: 'bold' as const },
      2: { textColor: [100, 100, 100] as [number,number,number], fontSize: 8 },
    },
  })
  y = (doc as any).lastAutoTable.finalY + 10

  // Notes for accountant
  y = chk(y, 60)
  doc.setFontSize(10); doc.setTextColor(60, 60, 60); doc.setFont('helvetica', 'bold')
  doc.text('NOTAS PARA EL CONTABLE', mL, y); doc.setFont('helvetica', 'normal'); y += 6
  doc.setFontSize(8); doc.setTextColor(100, 100, 100)
  const notes = [
    '• Los ingresos se clasifican por fecha del pago registrado en la app.',
    '• Las facturas se clasifican por fecha de pago (paid_date) cuando disponible, si no por fecha de creación.',
    '• Los gastos personales están separados y NO deben incluirse como deducciones.',
    '• La retención de Hacienda es estimada según los campos "retención" de pagos e facturas.',
    '• El IVU cobrado refleja el total de IVU en facturas del período; verificar contra planillas de Hacienda.',
    `• Cuentas por cobrar al ${formatDate(endDate)}: ${pendingInvoices.length} facturas, ${formatCurrency(arTotal)}.`,
    periodBankTxs.length > 0
      ? `• Conciliación bancaria incluye ${periodBankTxs.length} transacciones importadas de estados de cuenta.`
      : '• No hay estados de cuenta bancarios importados para este período.',
  ]
  notes.forEach(note => { doc.text(note, mL, y); y += 5 })

  addFooter()
  doc.save(`Reporte-Contable-${periodLabel.replace(/\s+/g, '_')}-${new Date().toISOString().split('T')[0]}.pdf`)
}

// ============ DELINQUENT CLIENTS / MOROSOS REPORT ============
export function generateDelinquentReport(invoices: Invoice[]) {
  const now = Date.now()
  const pending = invoices.filter(inv =>
    inv.type === 'invoice' && (inv.status === 'sent' || inv.status === 'overdue' || inv.status === 'draft')
  )

  const buckets = { current: [] as Invoice[], days31_60: [] as Invoice[], days61_90: [] as Invoice[], days90plus: [] as Invoice[] }
  pending.forEach(inv => {
    const daysOld = Math.floor((now - (inv.due_date || inv.created_at)) / 86400000)
    if (daysOld <= 30) buckets.current.push(inv)
    else if (daysOld <= 60) buckets.days31_60.push(inv)
    else if (daysOld <= 90) buckets.days61_90.push(inv)
    else buckets.days90plus.push(inv)
  })

  const doc = new jsPDF()
  const pageW = doc.internal.pageSize.getWidth()
  const pageH = doc.internal.pageSize.getHeight()
  const marginL = 20, marginR = 20

  try { doc.addImage(LOGO_BASE64, 'PNG', pageW - marginR - 40, 10, 40, 17) } catch { }

  doc.setFontSize(18); doc.setTextColor(0, 150, 150); doc.text(COMPANY_NAME, marginL, 18)
  doc.setFontSize(14); doc.setTextColor(40, 40, 40); doc.text('Reporte de Clientes Morosos', marginL, 28)
  doc.setFontSize(9); doc.setTextColor(100, 100, 100); doc.text(`Generado: ${formatDate(Date.now())}`, marginL, 34)

  const totalPending = pending.reduce((s, inv) => s + inv.total, 0)
  doc.setFontSize(12); doc.setTextColor(239, 68, 68); doc.setFont('helvetica', 'bold')
  doc.text(`Total Pendiente: ${formatCurrency(totalPending)}`, marginL, 42); doc.setFont('helvetica', 'normal')

  let y = 52
  const agingSummary = [
    ['0-30 días', buckets.current, [59, 130, 246]], ['31-60 días', buckets.days31_60, [245, 158, 11]],
    ['61-90 días', buckets.days61_90, [249, 115, 22]], ['90+ días', buckets.days90plus, [239, 68, 68]]
  ] as const

  doc.setFontSize(11); doc.setTextColor(30, 30, 30); doc.setFont('helvetica', 'bold')
  doc.text('Resumen de Aging', marginL, y); doc.setFont('helvetica', 'normal'); y += 7

  agingSummary.forEach(([label, invs, color]) => {
    const total = (invs as Invoice[]).reduce((s: number, inv: Invoice) => s + inv.total, 0)
    doc.setFontSize(10); doc.setTextColor(color[0], color[1], color[2])
    doc.text(`${label}: ${(invs as Invoice[]).length} factura(s) — ${formatCurrency(total)}`, marginL + 5, y); y += 6
  })

  y += 8
  if (pending.length > 0) {
    autoTable(doc, {
      startY: y,
      head: [['Factura', 'Cliente', 'Tel.', 'Emisión', 'Vence', 'Edad', 'Monto']],
      body: pending
        .sort((a, b) => Math.floor((now - (b.due_date || b.created_at)) / 86400000) - Math.floor((now - (a.due_date || a.created_at)) / 86400000))
        .map(inv => {
          const daysOld = Math.floor((now - (inv.due_date || inv.created_at)) / 86400000)
          return [inv.invoice_number, inv.client_name, inv.client_phone || '-', formatDateShort(inv.created_at),
            inv.due_date ? formatDateShort(inv.due_date) : '-', `${daysOld} días`, formatCurrency(inv.total)]
        }),
      headStyles: { fillColor: [0, 150, 150], textColor: [255, 255, 255], fontSize: 8 }, bodyStyles: { fontSize: 8 },
      didParseCell: (data) => {
        if (data.section === 'body' && data.column.index === 5) {
          const days = parseInt(data.cell.raw as string)
          if (days > 90) data.cell.styles.textColor = [239, 68, 68]
          else if (days > 60) data.cell.styles.textColor = [249, 115, 22]
          else if (days > 30) data.cell.styles.textColor = [245, 158, 11]
        }
      }
    })
  } else { doc.setFontSize(12); doc.setTextColor(34, 197, 94); doc.text('🎉 No hay facturas pendientes', marginL, y) }

  doc.setDrawColor(200, 200, 200); doc.setLineWidth(0.3); doc.line(marginL, pageH - 15, pageW - marginR, pageH - 15)
  doc.setFontSize(8); doc.setTextColor(150, 150, 150); doc.text(COMPANY_SLOGAN, pageW / 2, pageH - 8, { align: 'center' })
  doc.save(`Morosos-${new Date().toISOString().split('T')[0]}.pdf`)
}

// ============ CLIENT PROFITABILITY REPORT ============
export function generateClientProfitabilityReport(
  events: EventRecord[],
  clients: Client[],
  startDate: number,
  endDate: number,
  periodLabel: string
) {
  const filtered = events.filter(e => e.timestamp >= startDate && e.timestamp <= endDate && e.client_id != null)

  const byClient: Record<number, { name: string; income: number; expense: number; events: number }> = {}
  filtered.forEach(e => {
    const cid = e.client_id!
    if (!byClient[cid]) {
      const client = clients.find(c => c.id === cid)
      byClient[cid] = { name: client ? `${client.first_name} ${client.last_name}`.trim() : (e.client || `Cliente #${cid}`), income: 0, expense: 0, events: 0 }
    }
    byClient[cid].events++
    if (e.type === 'income') byClient[cid].income += e.amount
    else byClient[cid].expense += e.amount
  })

  const doc = new jsPDF()
  const pageW = doc.internal.pageSize.getWidth()
  const pageH = doc.internal.pageSize.getHeight()
  const marginL = 20, marginR = 20

  try { doc.addImage(LOGO_BASE64, 'PNG', pageW - marginR - 40, 10, 40, 17) } catch { }

  doc.setFontSize(18); doc.setTextColor(0, 150, 150); doc.text(COMPANY_NAME, marginL, 18)
  doc.setFontSize(13); doc.setTextColor(40, 40, 40); doc.text(`Rentabilidad por Cliente - ${periodLabel}`, marginL, 27)
  doc.setFontSize(9); doc.setTextColor(100, 100, 100); doc.text(`${formatDate(startDate)} - ${formatDate(endDate)}`, marginL, 33)

  const rows = Object.values(byClient)
    .sort((a, b) => (b.income - b.expense) - (a.income - a.expense))
    .map(c => {
      const profitVal = c.income - c.expense
      return [c.name, String(c.events), formatCurrency(c.income), formatCurrency(c.expense), formatCurrency(profitVal), c.income > 0 ? ((profitVal / c.income) * 100).toFixed(1) + '%' : 'N/A']
    })

  if (rows.length === 0) { doc.setFontSize(12); doc.text('No hay transacciones asociadas a clientes en este período.', marginL, 50) }
  else {
    autoTable(doc, {
      startY: 42,
      head: [['Cliente', '# Trans.', 'Ingresos', 'Gastos', 'Ganancia', 'Margen']],
      body: rows,
      headStyles: { fillColor: [0, 150, 150], textColor: [255, 255, 255], fontSize: 9 }, bodyStyles: { fontSize: 9 },
      didParseCell: (data) => {
        if (data.section === 'body' && data.column.index === 4) {
          const val = parseFloat((data.cell.raw as string).replace('$', '').replace(',', ''))
          if (val < 0) data.cell.styles.textColor = [239, 68, 68]
          else data.cell.styles.textColor = [34, 197, 94]
        }
      }
    })
  }

  doc.setDrawColor(200, 200, 200); doc.setLineWidth(0.3); doc.line(marginL, pageH - 15, pageW - marginR, pageH - 15)
  doc.setFontSize(8); doc.setTextColor(150, 150, 150); doc.text(COMPANY_SLOGAN, pageW / 2, pageH - 8, { align: 'center' })
  doc.save(`Rentabilidad-Clientes-${periodLabel.replace(/\s+/g, '-')}-${new Date().toISOString().split('T')[0]}.pdf`)
}

// ============ RECURRING CONTRACTS REPORT ============
export function generateContractsReport(
  contracts: RecurringContract[],
  clients: Client[]
) {
  const doc = new jsPDF()
  const pageW = doc.internal.pageSize.getWidth()
  const pageH = doc.internal.pageSize.getHeight()
  const marginL = 20, marginR = 20

  try { doc.addImage(LOGO_BASE64, 'PNG', pageW - marginR - 40, 10, 40, 17) } catch { }

  doc.setFontSize(18); doc.setTextColor(0, 150, 150); doc.text(COMPANY_NAME, marginL, 18)
  doc.setFontSize(14); doc.setTextColor(40, 40, 40); doc.text('Reporte de Contratos Recurrentes', marginL, 28)
  doc.setFontSize(9); doc.setTextColor(100, 100, 100); doc.text(`Generado: ${formatDate(Date.now())}`, marginL, 34)

  const active = contracts.filter(c => c.status === 'active')
  const cancelled = contracts.filter(c => c.status === 'cancelled')
  const freqLabels: Record<string, string> = { monthly: 'Mensual', quarterly: 'Trimestral' }

  const monthlyRevenue = active.reduce((s, c) => {
    if (c.frequency === 'monthly') return s + c.monthly_fee
    if (c.frequency === 'quarterly') return s + (c.monthly_fee / 3)
    return s + c.monthly_fee
  }, 0)

  let y = 44
  doc.setFontSize(11); doc.setTextColor(30, 30, 30); doc.setFont('helvetica', 'bold')
  doc.text('RESUMEN', marginL, y); doc.setFont('helvetica', 'normal'); y += 7
  doc.setFontSize(10)

  const contractItems: [string, string][] = [
    ['Contratos Activos', String(active.length)],
    ['Contratos Cancelados', String(cancelled.length)],
    ['Ingreso Recurrente Mensual', formatCurrency(monthlyRevenue)],
    ['Ingreso Recurrente Anual (est.)', formatCurrency(monthlyRevenue * 12)]
  ]
  contractItems.forEach(([label, value]) => {
    doc.setTextColor(60, 60, 60); doc.text(label, marginL + 5, y)
    doc.setTextColor(34, 197, 94); doc.setFont('helvetica', 'bold')
    doc.text(value, 130, y, { align: 'right' }); doc.setFont('helvetica', 'normal'); y += 6
  })

  y += 8
  doc.setFontSize(11); doc.setTextColor(34, 197, 94); doc.setFont('helvetica', 'bold')
  doc.text('CONTRATOS ACTIVOS', marginL, y); doc.setFont('helvetica', 'normal'); y += 3

  if (active.length > 0) {
    autoTable(doc, {
      startY: y,
      head: [['Cliente', 'Servicio', 'Frecuencia', 'Cuota', 'Próx. Servicio', 'Inicio']],
      body: active.map(c => {
        const client = clients.find(cl => cl.id === c.client_id)
        return [
          client ? `${client.first_name} ${client.last_name}`.trim() : `Cliente #${c.client_id}`,
          c.service_type || '-', freqLabels[c.frequency] || c.frequency,
          formatCurrency(c.monthly_fee), formatDateShort(c.next_service_due), formatDateShort(c.start_date)
        ]
      }),
      headStyles: { fillColor: [0, 150, 150], textColor: [255, 255, 255], fontSize: 8 }, bodyStyles: { fontSize: 8 }
    })
    y = (doc as any).lastAutoTable.finalY + 10
  } else { y += 5; doc.setFontSize(10); doc.setTextColor(100, 100, 100); doc.text('No hay contratos activos.', marginL + 5, y); y += 10 }

  if (cancelled.length > 0) {
    if (y > pageH - 60) { doc.addPage(); y = 20 }
    doc.setFontSize(11); doc.setTextColor(100, 100, 100); doc.setFont('helvetica', 'bold')
    doc.text('CONTRATOS CANCELADOS', marginL, y); doc.setFont('helvetica', 'normal'); y += 3
    autoTable(doc, {
      startY: y,
      head: [['Cliente', 'Servicio', 'Frecuencia', 'Cuota']],
      body: cancelled.map(c => {
        const client = clients.find(cl => cl.id === c.client_id)
        return [
          client ? `${client.first_name} ${client.last_name}`.trim() : `Cliente #${c.client_id}`,
          c.service_type || '-', freqLabels[c.frequency] || c.frequency, formatCurrency(c.monthly_fee)
        ]
      }),
      headStyles: { fillColor: [120, 120, 120], textColor: [255, 255, 255], fontSize: 8 },
      bodyStyles: { fontSize: 8, textColor: [120, 120, 120] }
    })
  }

  const totalPages = doc.getNumberOfPages()
  for (let i = 1; i <= totalPages; i++) {
    doc.setPage(i); doc.setDrawColor(200, 200, 200); doc.setLineWidth(0.3)
    doc.line(marginL, pageH - 15, pageW - marginR, pageH - 15)
    doc.setFontSize(8); doc.setTextColor(150, 150, 150)
    doc.text(COMPANY_SLOGAN, pageW / 2, pageH - 8, { align: 'center' })
    doc.text(`Página ${i} de ${totalPages}`, pageW - marginR, pageH - 8, { align: 'right' })
  }
  doc.save(`Contratos-Recurrentes-${new Date().toISOString().split('T')[0]}.pdf`)
}

// ============ CONTRACT SERVICE HISTORY PDF ============
export function generateContractServiceHistoryPDF(
  contract: RecurringContract,
  serviceRecords: ContractServiceRecord[]
) {
  const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'letter' })
  const fmt = (n: number) => `$${n.toFixed(2).replace(/\B(?=(\d{3})+(?!\d))/g, ',')}`
  const fmtDate = (ts: number) => new Date(ts).toLocaleDateString('es-PR', { year: 'numeric', month: '2-digit', day: '2-digit' })

  const FREQ_LABELS: Record<string, string> = {
    monthly: 'Mensual', bimonthly: 'Bimestral', quarterly: 'Trimestral',
    semiannual: 'Semestral', annual: 'Anual'
  }

  // Header
  doc.setFillColor(0, 100, 120)
  doc.rect(0, 0, 216, 32, 'F')
  doc.setFontSize(16); doc.setFont('helvetica', 'bold'); doc.setTextColor(255, 255, 255)
  doc.text(COMPANY_NAME, 14, 12)
  doc.setFontSize(10); doc.setFont('helvetica', 'normal')
  doc.text('Historial de Servicios — Contrato Recurrente', 14, 20)
  doc.text(`Generado: ${fmtDate(Date.now())}`, 14, 27)

  // Contract info box
  doc.setFontSize(13); doc.setFont('helvetica', 'bold'); doc.setTextColor(20, 20, 20)
  doc.text(contract.client_name || `Contrato #${contract.id}`, 14, 45)
  doc.setFontSize(9); doc.setFont('helvetica', 'normal'); doc.setTextColor(80, 80, 80)
  doc.text(`Servicio: ${contract.service_type}${contract.description ? ' — ' + contract.description : ''}`, 14, 52)
  if (contract.location_name) doc.text(`Localidad: ${contract.location_name}`, 14, 58)
  doc.text(`Frecuencia: ${FREQ_LABELS[contract.frequency] || contract.frequency} · Monto/visita: ${fmt(contract.monthly_fee)}`, 14, 65)
  doc.text(`Inicio: ${fmtDate(contract.start_date)}${contract.end_date ? ` · Vence: ${fmtDate(contract.end_date)}` : ''}`, 14, 72)

  // Summary box
  const sorted = [...serviceRecords].sort((a, b) => a.date - b.date)
  const totalPaid = sorted.reduce((s, r) => s + r.amount, 0)
  doc.setFillColor(240, 248, 255)
  doc.rect(14, 78, 183, 16, 'F')
  doc.setFontSize(9); doc.setFont('helvetica', 'bold'); doc.setTextColor(0, 80, 100)
  doc.text(`${sorted.length} servicios completados`, 20, 86)
  doc.text(`Total facturado: ${fmt(totalPaid)}`, 100, 86)
  if (sorted.length > 0) {
    doc.text(`Último: ${fmtDate(sorted[sorted.length - 1].date)}`, 160, 86)
  }

  // Services table
  autoTable(doc, {
    startY: 100,
    head: [['#', 'Fecha', 'Técnico', 'Notas', 'Monto']],
    body: sorted.map((r, i) => [
      String(i + 1),
      fmtDate(r.date),
      r.completed_by || '—',
      r.notes || '—',
      fmt(r.amount),
    ]),
    foot: [['', '', '', 'TOTAL', fmt(totalPaid)]],
    headStyles: { fillColor: [0, 100, 120], textColor: [255, 255, 255], fontSize: 9 },
    bodyStyles: { fontSize: 9 },
    footStyles: { fillColor: [220, 240, 245], fontStyle: 'bold', fontSize: 9 },
    columnStyles: {
      0: { cellWidth: 10, halign: 'center' },
      1: { cellWidth: 28 },
      2: { cellWidth: 35 },
      3: { cellWidth: 80 },
      4: { cellWidth: 28, halign: 'right' },
    },
    alternateRowStyles: { fillColor: [248, 252, 255] },
  })

  const finalY = (doc as any).lastAutoTable?.finalY || 180
  doc.setFontSize(7); doc.setTextColor(120, 120, 120)
  doc.text(`${COMPANY_NAME} · ${COMPANY_PHONE}`, 14, finalY + 10)

  const clientLabel = (contract.client_name || 'Contrato').replace(/\s+/g, '_')
  doc.save(`Historial_${clientLabel}_${new Date().toISOString().split('T')[0]}.pdf`)
}

// ============ PRODUCTIVITY / JOBS REPORT ============
export function generateProductivityReport(
  jobs: Job[],
  events: EventRecord[],
  clients: Client[],
  startDate: number,
  endDate: number,
  periodLabel: string
) {
  const doc = new jsPDF()
  const pageW = doc.internal.pageSize.getWidth()
  const pageH = doc.internal.pageSize.getHeight()
  const marginL = 20, marginR = 20

  const periodJobs = jobs.filter(j => j.date >= startDate && j.date <= endDate)
  const completedJobs = periodJobs.filter(j => j.status === 'completed')
  const activeJobs = periodJobs.filter(j => j.status === 'in_progress')
  const quoteJobs = periodJobs.filter(j => j.status === 'quote')

  const jobIncome = events.filter(e => e.timestamp >= startDate && e.timestamp <= endDate && e.type === 'income' && e.job_id != null)
  const totalJobRevenue = jobIncome.reduce((s, e) => s + e.amount, 0)
  const avgRevenuePerJob = completedJobs.length > 0 ? totalJobRevenue / completedJobs.length : 0

  const jobExpenses = events.filter(e => e.timestamp >= startDate && e.timestamp <= endDate && e.type === 'expense' && e.job_id != null)
  const totalJobExpense = jobExpenses.reduce((s, e) => s + e.amount, 0)
  const jobProfit = totalJobRevenue - totalJobExpense

  try { doc.addImage(LOGO_BASE64, 'PNG', pageW - marginR - 40, 10, 40, 17) } catch { }

  doc.setFontSize(18); doc.setTextColor(0, 150, 150); doc.text(COMPANY_NAME, marginL, 18)
  doc.setFontSize(13); doc.setTextColor(40, 40, 40); doc.text(`Productividad & Trabajos - ${periodLabel}`, marginL, 27)
  doc.setFontSize(9); doc.setTextColor(100, 100, 100)
  doc.text(`${formatDate(startDate)} - ${formatDate(endDate)}`, marginL, 33)
  doc.text(`Generado: ${formatDate(Date.now())}`, marginL, 38)

  let y = 48
  doc.setDrawColor(0, 150, 150); doc.setLineWidth(0.5); doc.line(marginL, y, pageW - marginR, y); y += 8
  doc.setFontSize(12); doc.setTextColor(30, 30, 30); doc.setFont('helvetica', 'bold')
  doc.text('INDICADORES CLAVE', marginL, y); doc.setFont('helvetica', 'normal'); y += 8

  const typeLabels: Record<string, string> = {
    installation: 'Instalación', repair: 'Reparación', maintenance: 'Mantenimiento',
    emergency: 'Emergencia', warranty: 'Garantía', quote: 'Cotización'
  }

  const statusLabels: Record<string, string> = {
    quote: 'Cotización', in_progress: 'En Progreso', completed: 'Completado', cancelled: 'Cancelado'
  }

  const kpis: [string, string][] = [
    ['Total Trabajos', String(periodJobs.length)],
    ['Completados', String(completedJobs.length)],
    ['En Progreso', String(activeJobs.length)],
    ['Cotizaciones', String(quoteJobs.length)],
    ['Tasa de Completación', periodJobs.length > 0 ? ((completedJobs.length / periodJobs.length) * 100).toFixed(0) + '%' : 'N/A'],
    ['', ''],
    ['Ingreso por Trabajos', formatCurrency(totalJobRevenue)],
    ['Gastos en Trabajos', formatCurrency(totalJobExpense)],
    ['Ganancia en Trabajos', formatCurrency(jobProfit)],
    ['Ingreso Promedio/Trabajo', formatCurrency(avgRevenuePerJob)],
    ['Margen por Trabajo', totalJobRevenue > 0 ? ((jobProfit / totalJobRevenue) * 100).toFixed(1) + '%' : 'N/A']
  ]

  doc.setFontSize(10)
  kpis.forEach(([label, value]) => {
    if (label === '') { y += 4; return }
    doc.setTextColor(60, 60, 60); doc.text(label, marginL + 5, y)
    doc.setTextColor(30, 30, 30); doc.setFont('helvetica', 'bold')
    doc.text(value, 130, y, { align: 'right' }); doc.setFont('helvetica', 'normal'); y += 6
  })

  y += 10; if (y > pageH - 60) { doc.addPage(); y = 20 }
  doc.setFontSize(11); doc.setTextColor(30, 30, 30); doc.setFont('helvetica', 'bold')
  doc.text('DETALLE DE TRABAJOS', marginL, y); doc.setFont('helvetica', 'normal'); y += 3

  if (periodJobs.length > 0) {
    autoTable(doc, {
      startY: y,
      head: [['Fecha', 'Cliente', 'Tipo', 'Status', 'Cobrado', 'Balance']],
      body: periodJobs.sort((a, b) => b.date - a.date).map(j => {
        const client = clients.find(c => c.id === j.client_id)
        const clientName = client ? `${client.first_name} ${client.last_name}`.trim() : `Cliente #${j.client_id}`
        return [
          formatDateShort(j.date), clientName, typeLabels[j.type] || j.type,
          statusLabels[j.status] || j.status, formatCurrency(j.total_charged), formatCurrency(j.balance_due)
        ]
      }),
      headStyles: { fillColor: [0, 150, 150], textColor: [255, 255, 255], fontSize: 8 },
      bodyStyles: { fontSize: 8 },
      didParseCell: (data) => {
        if (data.section === 'body' && data.column.index === 3) {
          const status = data.cell.raw as string
          if (status === 'Completado') data.cell.styles.textColor = [34, 197, 94]
          else if (status === 'Cancelado') data.cell.styles.textColor = [239, 68, 68]
          else data.cell.styles.textColor = [59, 130, 246]
        }
        if (data.section === 'body' && data.column.index === 5) {
          const val = parseFloat((data.cell.raw as string).replace('$', '').replace(',', ''))
          if (val > 0) data.cell.styles.textColor = [239, 68, 68]
          else data.cell.styles.textColor = [34, 197, 94]
        }
      }
    })
  } else { y += 5; doc.setFontSize(10); doc.setTextColor(100, 100, 100); doc.text('No hay trabajos en este período.', marginL + 5, y) }

  const totalPages = doc.getNumberOfPages()
  for (let i = 1; i <= totalPages; i++) {
    doc.setPage(i); doc.setDrawColor(200, 200, 200); doc.setLineWidth(0.3)
    doc.line(marginL, pageH - 15, pageW - marginR, pageH - 15)
    doc.setFontSize(8); doc.setTextColor(150, 150, 150)
    doc.text(COMPANY_SLOGAN, pageW / 2, pageH - 8, { align: 'center' })
    doc.text(`Página ${i} de ${totalPages}`, pageW - marginR, pageH - 8, { align: 'right' })
  }
  doc.save(`Productividad-${periodLabel.replace(/\s+/g, '-')}-${new Date().toISOString().split('T')[0]}.pdf`)
}

