// ============ INCOME BY CLIENT REPORT ============
export function generateIncomeByClientReport(
  events: EventRecord[],
  clients: Client[],
  startDate: number,
  endDate: number,
  periodLabel: string
) {
  const income = events.filter(e =>
    e.timestamp >= startDate &&
    e.timestamp <= endDate &&
    e.type === 'income'
  )

  const byClient: Record<string, { total: number; count: number; retention: number; events: EventRecord[] }> = {}
  income.forEach(e => {
    const name = e.client || 'Sin cliente'
    if (!byClient[name]) byClient[name] = { total: 0, count: 0, retention: 0, events: [] }
    byClient[name].total += e.amount
    byClient[name].count++
    byClient[name].retention += e.retention_amount || 0
    byClient[name].events.push(e)
  })

  const totalIncome = income.reduce((s, e) => s + e.amount, 0)
  const totalRetention = Object.values(byClient).reduce((s, c) => s + c.retention, 0)

  const doc = new jsPDF()
  const pageW = doc.internal.pageSize.getWidth()
  const pageH = doc.internal.pageSize.getHeight()
  const marginL = 20, marginR = 20

  try { doc.addImage(LOGO_BASE64, 'PNG', pageW - marginR - 40, 10, 40, 17) } catch { }

  doc.setFontSize(18); doc.setTextColor(0, 150, 150); doc.text(COMPANY_NAME, marginL, 18)
  doc.setFontSize(13); doc.setTextColor(40, 40, 40); doc.text(`Ingresos por Cliente — ${periodLabel}`, marginL, 27)
  doc.setFontSize(9); doc.setTextColor(100, 100, 100)
  doc.text(`${formatDate(startDate)} — ${formatDate(endDate)}`, marginL, 33)
  doc.text(`Generado: ${formatDate(Date.now())}`, marginL, 38)

  let y = 48
  doc.setDrawColor(0, 150, 150); doc.setLineWidth(0.5); doc.line(marginL, y, pageW - marginR, y); y += 8

  // Summary
  doc.setFontSize(12); doc.setTextColor(30, 30, 30); doc.setFont('helvetica', 'bold')
  doc.text('RESUMEN', marginL, y); doc.setFont('helvetica', 'normal'); y += 8
  doc.setFontSize(10)
  doc.setTextColor(60, 60, 60); doc.text('Total Recibido', marginL + 5, y)
  doc.setTextColor(34, 197, 94); doc.setFont('helvetica', 'bold')
  doc.text(formatCurrency(totalIncome), 130, y, { align: 'right' }); doc.setFont('helvetica', 'normal'); y += 6

  if (totalRetention > 0) {
    doc.setTextColor(60, 60, 60); doc.text('Retención Hacienda (estimada)', marginL + 5, y)
    doc.setTextColor(239, 68, 68); doc.text(formatCurrency(totalRetention), 130, y, { align: 'right' }); y += 6
    doc.setTextColor(60, 60, 60); doc.text('Total Facturado (estimado)', marginL + 5, y)
    doc.setTextColor(30, 30, 30); doc.setFont('helvetica', 'bold')
    doc.text(formatCurrency(totalIncome + totalRetention), 130, y, { align: 'right' }); doc.setFont('helvetica', 'normal'); y += 6
  }

  doc.setTextColor(60, 60, 60); doc.text('Total Clientes', marginL + 5, y)
  doc.text(String(Object.keys(byClient).length), 130, y, { align: 'right' }); y += 6
  doc.text('Total Pagos', marginL + 5, y)
  doc.text(String(income.length), 130, y, { align: 'right' }); y += 12

  // Table
  const rows = Object.entries(byClient)
    .sort((a, b) => b[1].total - a[1].total)
    .map(([name, data]) => {
      const row = [
        name,
        String(data.count),
        formatCurrency(data.total),
      ]
      if (data.retention > 0) {
        row.push(formatCurrency(data.retention))
        row.push(formatCurrency(data.total + data.retention))
      } else {
        row.push('-')
        row.push('-')
      }
      return row
    })

  autoTable(doc, {
    startY: y,
    head: [['Cliente', '# Pagos', 'Recibido', 'Retención', 'Facturado']],
    body: rows,
    headStyles: { fillColor: [0, 150, 150], textColor: [255, 255, 255], fontSize: 9 },
    bodyStyles: { fontSize: 9 },
    columnStyles: {
      0: { cellWidth: 55 },
      2: { halign: 'right' as const },
      3: { halign: 'right' as const },
      4: { halign: 'right' as const }
    }
  })

  // Detail per client
  let detailY = (doc as any).lastAutoTable.finalY + 15

  Object.entries(byClient)
    .sort((a, b) => b[1].total - a[1].total)
    .forEach(([name, data]) => {
      if (detailY > pageH - 60) { doc.addPage(); detailY = 20 }
      doc.setFontSize(10); doc.setTextColor(0, 150, 150); doc.setFont('helvetica', 'bold')
      doc.text(`${name} — ${formatCurrency(data.total)}`, marginL, detailY)
      if (data.retention > 0) {
        doc.setTextColor(239, 68, 68); doc.setFontSize(8)
        doc.text(`(Retención: ${formatCurrency(data.retention)})`, marginL + 90, detailY)
      }
      doc.setFont('helvetica', 'normal')

      autoTable(doc, {
        startY: detailY + 3,
        head: [['Fecha', 'Monto', 'Método', 'Nota']],
        body: data.events.sort((a, b) => a.timestamp - b.timestamp).map(e => [
          formatDateShort(e.timestamp),
          formatCurrency(e.amount),
          getPaymentLabel(e.payment_method),
          e.note || '-'
        ]),
        headStyles: { fillColor: [60, 60, 60], textColor: [255, 255, 255], fontSize: 8 },
        bodyStyles: { fontSize: 8 },
        margin: { left: marginL + 5 }
      })
      detailY = (doc as any).lastAutoTable.finalY + 12
    })

  const totalPages = doc.getNumberOfPages()
  for (let i = 1; i <= totalPages; i++) {
    doc.setPage(i); doc.setDrawColor(200, 200, 200); doc.setLineWidth(0.3)
    doc.line(marginL, pageH - 15, pageW - marginR, pageH - 15)
    doc.setFontSize(8); doc.setTextColor(150, 150, 150)
    doc.text(COMPANY_SLOGAN, pageW / 2, pageH - 8, { align: 'center' })
    doc.text(`Página ${i} de ${totalPages}`, pageW - marginR, pageH - 8, { align: 'right' })
  }

  doc.save(`Ingresos-por-Cliente-${periodLabel.replace(/\s+/g, '-')}-${new Date().toISOString().split('T')[0]}.pdf`)
}

// PEGA ESTO EN pdfGenerator.ts ANTES DE export function exportEventsCSV

export function generateReconciliationReport(
  events: EventRecord[],
  startDate: number,
  endDate: number,
  periodLabel: string,
  cardFilter?: string
) {
  const expenses = events.filter(e =>
    e.timestamp >= startDate && e.timestamp <= endDate && e.type === 'expense'
  ).sort((a, b) => a.timestamp - b.timestamp)

  const income = events.filter(e =>
    e.timestamp >= startDate && e.timestamp <= endDate && e.type === 'income'
  ).sort((a, b) => a.timestamp - b.timestamp)

  const doc = new jsPDF()
  const pageW = doc.internal.pageSize.getWidth()
  const pageH = doc.internal.pageSize.getHeight()
  const marginL = 15, marginR = 15

  const addFooter = () => {
    const totalPages = doc.getNumberOfPages()
    for (let i = 1; i <= totalPages; i++) {
      doc.setPage(i)
      doc.setDrawColor(200, 200, 200); doc.setLineWidth(0.3)
      doc.line(marginL, pageH - 15, pageW - marginR, pageH - 15)
      doc.setFontSize(8); doc.setTextColor(150, 150, 150)
      doc.text(COMPANY_SLOGAN, pageW / 2, pageH - 8, { align: 'center' })
      doc.text(`Página ${i} de ${totalPages}`, pageW - marginR, pageH - 8, { align: 'right' })
    }
  }

  // === HEADER ===
  try { doc.addImage(LOGO_BASE64, 'PNG', pageW - marginR - 40, 10, 40, 17) } catch { }
  doc.setFontSize(16); doc.setTextColor(0, 150, 150); doc.text(COMPANY_NAME, marginL, 18)
  doc.setFontSize(12); doc.setTextColor(40, 40, 40); doc.text(`Conciliación Bancaria — ${periodLabel}`, marginL, 27)
  doc.setFontSize(9); doc.setTextColor(100, 100, 100)
  doc.text(`${formatDate(startDate)} — ${formatDate(endDate)}`, marginL, 33)
  doc.text(`Generado: ${formatDate(Date.now())}`, marginL, 38)

  let y = 48

  // === RESUMEN GENERAL ===
  const totalExpenses = expenses.reduce((s, e) => s + e.amount, 0)
  const totalIncome = income.reduce((s, e) => s + e.amount, 0)

  doc.setDrawColor(0, 150, 150); doc.setLineWidth(0.5); doc.line(marginL, y, pageW - marginR, y)
  y += 8
  doc.setFontSize(11); doc.setTextColor(30, 30, 30); doc.setFont('helvetica', 'bold')
  doc.text('RESUMEN GENERAL', marginL, y); doc.setFont('helvetica', 'normal'); y += 7
  doc.setFontSize(10)
  doc.setTextColor(220, 50, 50); doc.text(`Total Gastos: ${formatCurrency(totalExpenses)} (${expenses.length} transacciones)`, marginL + 5, y); y += 6
  doc.setTextColor(34, 197, 94); doc.text(`Total Ingresos: ${formatCurrency(totalIncome)} (${income.length} depósitos)`, marginL + 5, y); y += 6
  const net = totalIncome - totalExpenses
  doc.setTextColor(net >= 0 ? 34 : 220, net >= 0 ? 197 : 50, net >= 0 ? 94 : 50)
  doc.setFont('helvetica', 'bold')
  doc.text(`Neto: ${formatCurrency(net)}`, marginL + 5, y)
  doc.setFont('helvetica', 'normal'); y += 12

  // =============================================
  // SECCIÓN 1: GASTOS POR TARJETA
  // =============================================
  doc.setFontSize(13); doc.setTextColor(0, 150, 150); doc.setFont('helvetica', 'bold')
  doc.text('GASTOS POR TARJETA / MÉTODO DE PAGO', marginL, y)
  doc.setFont('helvetica', 'normal'); y += 8

  // Agrupar por método de pago
  const byCard: Record<string, EventRecord[]> = {}
  expenses.forEach(e => {
    const method = e.payment_method || 'cash'
    if (!byCard[method]) byCard[method] = []
    byCard[method].push(e)
  })

  // Resumen por tarjeta
  const cardSummary = Object.entries(byCard)
    .sort((a, b) => b[1].reduce((s, e) => s + e.amount, 0) - a[1].reduce((s, e) => s + e.amount, 0))
    .map(([method, evts]) => [
      getPaymentLabel(method),
      String(evts.length),
      formatCurrency(evts.reduce((s, e) => s + e.amount, 0))
    ])

  autoTable(doc, {
    startY: y,
    head: [['Tarjeta / Método', '# Transacciones', 'Total']],
    body: cardSummary,
    headStyles: { fillColor: [0, 150, 150], textColor: [255, 255, 255], fontSize: 9 },
    bodyStyles: { fontSize: 9 },
    columnStyles: { 2: { halign: 'right' as const } }
  })
  y = (doc as any).lastAutoTable.finalY + 12

  // Detalle por cada tarjeta
  const cardOrder = cardFilter
    ? Object.entries(byCard).filter(([m]) => m === cardFilter)
    : Object.entries(byCard).sort((a, b) =>
        b[1].reduce((s, e) => s + e.amount, 0) - a[1].reduce((s, e) => s + e.amount, 0)
      )

  cardOrder.forEach(([method, evts]) => {
    const cardTotal = evts.reduce((s, e) => s + e.amount, 0)

    if (y > pageH - 60) { doc.addPage(); y = 20 }

    // Card header
    doc.setFontSize(11); doc.setTextColor(0, 100, 150); doc.setFont('helvetica', 'bold')
    doc.text(`💳 ${getPaymentLabel(method)} — ${formatCurrency(cardTotal)} (${evts.length} cargos)`, marginL, y)
    doc.setFont('helvetica', 'normal'); y += 3

    // Agrupar por mes dentro de la tarjeta
    const byMonth: Record<string, EventRecord[]> = {}
    evts.forEach(e => {
      const d = new Date(e.timestamp)
      const key = d.toLocaleDateString('es-PR', { year: 'numeric', month: 'long' })
      if (!byMonth[key]) byMonth[key] = []
      byMonth[key].push(e)
    })

    Object.entries(byMonth).forEach(([month, monthEvts]) => {
      const monthTotal = monthEvts.reduce((s, e) => s + e.amount, 0)

      if (y > pageH - 40) { doc.addPage(); y = 20 }

      autoTable(doc, {
        startY: y,
        head: [[`${month} — ${getPaymentLabel(method)}`, 'Categoría', 'Cliente', 'Monto']],
        body: monthEvts.sort((a, b) => a.timestamp - b.timestamp).map(e => [
          `${formatDateShort(e.timestamp)} — ${e.vendor || e.note || '-'}`,
          e.category || '-',
          e.client || '-',
          formatCurrency(e.amount)
        ]),
        foot: [['', '', `Total ${month}:`, formatCurrency(monthTotal)]],
        headStyles: { fillColor: [60, 80, 120], textColor: [255, 255, 255], fontSize: 8 },
        bodyStyles: { fontSize: 8 },
        footStyles: { fillColor: [240, 240, 240], textColor: [30, 30, 30], fontSize: 8, fontStyle: 'bold' },
        columnStyles: {
          0: { cellWidth: 65 },
          3: { halign: 'right' as const, cellWidth: 25 }
        }
      })
      y = (doc as any).lastAutoTable.finalY + 8
    })

    y += 5
  })

  // =============================================
  // SECCIÓN 2: INGRESOS / DEPÓSITOS (Oriental Bank)
  // =============================================
  if (income.length > 0) {
    doc.addPage(); y = 20

    doc.setFontSize(13); doc.setTextColor(0, 150, 150); doc.setFont('helvetica', 'bold')
    doc.text('INGRESOS / DEPÓSITOS — Oriental Bank', marginL, y)
    doc.setFont('helvetica', 'normal'); y += 3

    doc.setFontSize(9); doc.setTextColor(100, 100, 100)
    doc.text('Compare esta lista con el estado de cuenta de Oriental Bank', marginL, y + 5)
    y += 12

    // Resumen por método de cobro
    const byIncomeMethod: Record<string, { total: number; count: number }> = {}
    income.forEach(e => {
      const m = getPaymentLabel(e.payment_method) || 'Sin método'
      if (!byIncomeMethod[m]) byIncomeMethod[m] = { total: 0, count: 0 }
      byIncomeMethod[m].total += e.amount
      byIncomeMethod[m].count++
    })

    autoTable(doc, {
      startY: y,
      head: [['Método de Cobro', '# Depósitos', 'Total']],
      body: Object.entries(byIncomeMethod)
        .sort((a, b) => b[1].total - a[1].total)
        .map(([m, d]) => [m, String(d.count), formatCurrency(d.total)]),
      headStyles: { fillColor: [34, 140, 94], textColor: [255, 255, 255], fontSize: 9 },
      bodyStyles: { fontSize: 9 },
      columnStyles: { 2: { halign: 'right' as const } }
    })
    y = (doc as any).lastAutoTable.finalY + 10

    // Agrupar ingresos por mes
    const incByMonth: Record<string, EventRecord[]> = {}
    income.forEach(e => {
      const d = new Date(e.timestamp)
      const key = d.toLocaleDateString('es-PR', { year: 'numeric', month: 'long' })
      if (!incByMonth[key]) incByMonth[key] = []
      incByMonth[key].push(e)
    })

    Object.entries(incByMonth).forEach(([month, monthInc]) => {
      const monthTotal = monthInc.reduce((s, e) => s + e.amount, 0)

      if (y > pageH - 40) { doc.addPage(); y = 20 }

      autoTable(doc, {
        startY: y,
        head: [[`${month} — Ingresos`, 'Cliente', 'Método', 'Monto']],
        body: monthInc.sort((a, b) => a.timestamp - b.timestamp).map(e => [
          `${formatDateShort(e.timestamp)} — ${e.note || '-'}`,
          e.client || '-',
          getPaymentLabel(e.payment_method),
          formatCurrency(e.amount)
        ]),
        foot: [['', '', `Total ${month}:`, formatCurrency(monthTotal)]],
        headStyles: { fillColor: [34, 140, 94], textColor: [255, 255, 255], fontSize: 8 },
        bodyStyles: { fontSize: 8 },
        footStyles: { fillColor: [240, 248, 240], textColor: [30, 30, 30], fontSize: 8, fontStyle: 'bold' },
        columnStyles: {
          0: { cellWidth: 55 },
          3: { halign: 'right' as const, cellWidth: 25 }
        }
      })
      y = (doc as any).lastAutoTable.finalY + 8
    })

    // Resumen por cliente
    y += 5
    if (y > pageH - 60) { doc.addPage(); y = 20 }

    const incByClient: Record<string, { total: number; count: number }> = {}
    income.forEach(e => {
      const cl = e.client || 'Sin cliente'
      if (!incByClient[cl]) incByClient[cl] = { total: 0, count: 0 }
      incByClient[cl].total += e.amount
      incByClient[cl].count++
    })

    autoTable(doc, {
      startY: y,
      head: [['Cliente', '# Pagos', 'Total Recibido']],
      body: Object.entries(incByClient)
        .sort((a, b) => b[1].total - a[1].total)
        .map(([cl, d]) => [cl, String(d.count), formatCurrency(d.total)]),
      headStyles: { fillColor: [34, 140, 94], textColor: [255, 255, 255], fontSize: 9 },
      bodyStyles: { fontSize: 9 },
      columnStyles: { 2: { halign: 'right' as const } }
    })
  }

  // === FOOTERS ===
  addFooter()

  const suffix = cardFilter ? `-${getPaymentLabel(cardFilter).replace(/\s+/g, '-')}` : ''
  doc.save(`Conciliacion${suffix}-${periodLabel.replace(/\s+/g, '-')}-${new Date().toISOString().split('T')[0]}.pdf`)
}
// ============ BANK RECONCILIATION PDF (bank_transactions vs events) ============
export function generateBankReconciliationPDF(
  bankTxs: any[],
  events: EventRecord[],
  accounts: any[],
  filterAccountName?: string,
  filterStart?: number,
  filterEnd?: number,
  statements?: any[]
) {
  const doc = new jsPDF()
  const pageW = doc.internal.pageSize.getWidth()
  const pageH = doc.internal.pageSize.getHeight()
  const mL = 14, mR = 14

  const addFooter = () => {
    const total = doc.getNumberOfPages()
    for (let i = 1; i <= total; i++) {
      doc.setPage(i)
      doc.setDrawColor(200, 200, 200); doc.setLineWidth(0.3)
      doc.line(mL, pageH - 14, pageW - mR, pageH - 14)
      doc.setFontSize(8); doc.setTextColor(150, 150, 150)
      doc.text(COMPANY_SLOGAN, pageW / 2, pageH - 7, { align: 'center' })
      doc.text(`Pág ${i} de ${total}`, pageW - mR, pageH - 7, { align: 'right' })
    }
  }

  const periodTxs = bankTxs.filter(t => {
    if (filterAccountName && t.account_name !== filterAccountName) return false
    if (filterStart && t.date < filterStart) return false
    if (filterEnd && t.date > filterEnd) return false
    return true
  })
  const periodEvents = events.filter(e => {
    if (filterStart && e.timestamp < filterStart) return false
    if (filterEnd && e.timestamp > filterEnd) return false
    return true
  })

  const startLabel = filterStart ? formatDate(filterStart) : 'todo'
  const endLabel = filterEnd ? formatDate(filterEnd) : 'todo'
  const accountLabel = filterAccountName
    ? (accounts.find(a => a.payment_method_key === filterAccountName)?.name || filterAccountName)
    : 'Todas las cuentas'

  // Header
  try { doc.addImage(LOGO_BASE64, 'PNG', pageW - mR - 38, 8, 38, 16) } catch {}
  doc.setFontSize(15); doc.setTextColor(0, 130, 130); doc.text(COMPANY_NAME, mL, 17)
  doc.setFontSize(11); doc.setTextColor(40, 40, 40); doc.text('Conciliación Bancaria', mL, 25)
  doc.setFontSize(9); doc.setTextColor(100, 100, 100)
  doc.text(`Cuenta: ${accountLabel}  |  Período: ${startLabel} — ${endLabel}`, mL, 31)
  doc.text(`Generado: ${formatDate(Date.now())}`, mL, 36)

  let y = 44

  // Group transactions by account
  const byAccount: Record<string, any[]> = {}
  for (const tx of periodTxs) {
    if (!byAccount[tx.account_name]) byAccount[tx.account_name] = []
    byAccount[tx.account_name].push(tx)
  }

  for (const [acctName, txList] of Object.entries(byAccount)) {
    const acct = accounts.find((a: any) => a.payment_method_key === acctName)
    const acctLabel = acct?.name || acctName

    if (y > pageH - 60) { doc.addPage(); y = 20 }

    doc.setDrawColor(0, 130, 130); doc.setLineWidth(0.5)
    doc.line(mL, y, pageW - mR, y); y += 7

    doc.setFontSize(12); doc.setTextColor(0, 100, 130); doc.setFont('helvetica', 'bold')
    doc.text(`🏦 ${acctLabel}`, mL, y)
    doc.setFont('helvetica', 'normal'); y += 5

    const matched = txList.filter(t => t.match_status === 'matched').length
    const unmatched = txList.filter(t => t.match_status === 'unmatched').length
    const probable = txList.filter(t => t.match_status === 'probable').length
    const totalDebits = txList.filter(t => t.direction === 'debit').reduce((s: number, t: any) => s + t.amount, 0)
    const totalCredits = txList.filter(t => t.direction === 'credit').reduce((s: number, t: any) => s + t.amount, 0)

    autoTable(doc, {
      startY: y,
      head: [['Transacciones', 'Conciliadas', 'Sin match', 'Probables', 'Total Débitos', 'Total Créditos']],
      body: [[
        String(txList.length),
        String(matched),
        String(unmatched),
        String(probable),
        formatCurrency(totalDebits),
        formatCurrency(totalCredits),
      ]],
      headStyles: { fillColor: [0, 130, 130], textColor: [255, 255, 255], fontSize: 8 },
      bodyStyles: { fontSize: 8 },
      columnStyles: { 4: { halign: 'right' as const }, 5: { halign: 'right' as const } },
    })
    y = (doc as any).lastAutoTable.finalY + 6

    // Transactions table
    const rows = txList
      .sort((a: any, b: any) => a.date - b.date)
      .map((tx: any) => {
        const ev = tx.match_event_id ? events.find(e => e.id === tx.match_event_id) : null
        const statusIcon = tx.match_status === 'matched' ? '✓' : tx.match_status === 'probable' ? '?' : '⚠'
        return [
          formatDateShort(tx.date),
          tx.description.length > 28 ? tx.description.slice(0, 28) + '…' : tx.description,
          tx.direction === 'debit' ? `-${formatCurrency(tx.amount)}` : `+${formatCurrency(tx.amount)}`,
          ev ? (ev.vendor || ev.client || ev.category || '').slice(0, 22) : '—',
          ev ? (ev.type === 'expense' ? `-${formatCurrency(ev.amount)}` : `+${formatCurrency(ev.amount)}`) : '—',
          ev ? formatCurrency(Math.abs(tx.amount - ev.amount)) : '—',
          statusIcon + ' ' + (tx.match_status === 'matched' ? 'OK' : tx.match_status === 'probable' ? 'Probable' : 'Sin match'),
        ]
      })

    autoTable(doc, {
      startY: y,
      head: [['Fecha', 'Descripción banco', 'Monto banco', 'Evento app', 'Monto app', 'Dif.', 'Estado']],
      body: rows,
      headStyles: { fillColor: [50, 80, 120], textColor: [255, 255, 255], fontSize: 7 },
      bodyStyles: { fontSize: 7 },
      columnStyles: {
        0: { cellWidth: 18 },
        1: { cellWidth: 52 },
        2: { halign: 'right' as const, cellWidth: 22 },
        3: { cellWidth: 40 },
        4: { halign: 'right' as const, cellWidth: 22 },
        5: { halign: 'right' as const, cellWidth: 14 },
        6: { cellWidth: 20 },
      },
      didParseCell: (data: any) => {
        if (data.section === 'body' && data.column.index === 6) {
          const status = data.cell.raw as string
          if (status.startsWith('✓')) data.cell.styles.textColor = [34, 150, 34]
          else if (status.startsWith('⚠')) data.cell.styles.textColor = [200, 50, 50]
          else data.cell.styles.textColor = [180, 140, 0]
        }
      }
    })
    y = (doc as any).lastAutoTable.finalY + 10
  }

  // Unmatched app events
  const matchedEventIds = new Set(periodTxs.filter(t => t.match_event_id).map(t => t.match_event_id))
  const unmatchedEvents = periodEvents.filter(e => e.type === 'expense' && !matchedEventIds.has(e.id))

  if (unmatchedEvents.length > 0) {
    if (y > pageH - 60) { doc.addPage(); y = 20 }
    doc.setDrawColor(200, 80, 80); doc.setLineWidth(0.4); doc.line(mL, y, pageW - mR, y); y += 7
    doc.setFontSize(11); doc.setTextColor(180, 50, 50); doc.setFont('helvetica', 'bold')
    doc.text(`⚠ Gastos sin transacción bancaria (${unmatchedEvents.length})`, mL, y)
    doc.setFont('helvetica', 'normal'); y += 4

    autoTable(doc, {
      startY: y,
      head: [['Fecha', 'Vendor / Cliente', 'Categoría', 'Método Pago', 'Monto']],
      body: unmatchedEvents.sort((a, b) => a.timestamp - b.timestamp).map(e => [
        formatDateShort(e.timestamp),
        (e.vendor || e.client || '—').slice(0, 30),
        e.category || '—',
        getPaymentLabel(e.payment_method),
        formatCurrency(e.amount),
      ]),
      headStyles: { fillColor: [180, 50, 50], textColor: [255, 255, 255], fontSize: 8 },
      bodyStyles: { fontSize: 8 },
      columnStyles: { 4: { halign: 'right' as const } },
    })
    y = (doc as any).lastAutoTable.finalY + 10
  }

  // Statements index
  if (statements && statements.length > 0) {
    if (y > pageH - 50) { doc.addPage(); y = 20 }
    doc.setDrawColor(180, 180, 180); doc.setLineWidth(0.3); doc.line(mL, y, pageW - mR, y); y += 7
    doc.setFontSize(10); doc.setTextColor(80, 80, 80); doc.setFont('helvetica', 'bold')
    doc.text('ESTADOS DISPONIBLES', mL, y); doc.setFont('helvetica', 'normal'); y += 4

    const filteredStmts = filterAccountName
      ? statements.filter((s: any) => s.account_name === filterAccountName)
      : statements
    autoTable(doc, {
      startY: y,
      head: [['Cuenta', 'Período', 'Transacciones', 'Subido']],
      body: filteredStmts.map((s: any) => {
        const acct = accounts.find((a: any) => a.payment_method_key === s.account_name)
        return [
          acct?.name || s.account_name,
          s.period_label || `${formatDateShort(s.period_start)} — ${formatDateShort(s.period_end)}`,
          String(s.tx_count || '—'),
          formatDateShort(s.created_at),
        ]
      }),
      headStyles: { fillColor: [100, 100, 100], textColor: [255, 255, 255], fontSize: 8 },
      bodyStyles: { fontSize: 8 },
    })
  }

  addFooter()
  const suffix = filterAccountName ? `-${filterAccountName}` : ''
  doc.save(`Conciliacion-Bancaria${suffix}-${new Date().toISOString().split('T')[0]}.pdf`)
}

// ============ MAINTENANCE / EQUIPMENT REPORT ============
export function generateMaintenancePDF(
  equipment: any[],
  logs: any[],
  clientFilter?: string
) {
  const doc = new jsPDF()
  const pageW = doc.internal.pageSize.getWidth()
  const pageH = doc.internal.pageSize.getHeight()
  const mL = 14, mR = 14
  const now = Date.now()
  const THIRTY = 30 * 86400000

  const statusColor = (eq: any): [number, number, number] => {
    if (!eq.next_service_due) return [120, 120, 120]
    if (eq.next_service_due < now) return [200, 50, 50]
    if (eq.next_service_due - now <= THIRTY) return [180, 140, 0]
    return [34, 140, 34]
  }
  const statusLabel = (eq: any): string => {
    if (!eq.next_service_due) return 'Sin programa'
    if (eq.next_service_due < now) return 'VENCIDO'
    if (eq.next_service_due - now <= THIRTY) return 'Próximo'
    return 'Al día'
  }
  const intervalLabel = (m: number): string =>
    m === 1 ? 'Mensual' : m === 3 ? 'Trimestral' : m === 6 ? 'Semestral' : 'Anual'

  const addFooter = () => {
    const total = doc.getNumberOfPages()
    for (let i = 1; i <= total; i++) {
      doc.setPage(i)
      doc.setDrawColor(200, 200, 200); doc.setLineWidth(0.3)
      doc.line(mL, pageH - 14, pageW - mR, pageH - 14)
      doc.setFontSize(8); doc.setTextColor(150, 150, 150)
      doc.text(COMPANY_SLOGAN, pageW / 2, pageH - 7, { align: 'center' })
      doc.text(`Pág ${i} de ${total}`, pageW - mR, pageH - 7, { align: 'right' })
    }
  }

  const filtered = clientFilter
    ? equipment.filter(e => e.client_name === clientFilter)
    : equipment

  // Header
  try { doc.addImage(LOGO_BASE64, 'PNG', pageW - mR - 40, 8, 40, 17) } catch {}
  doc.setFontSize(16); doc.setTextColor(0, 130, 130); doc.setFont('helvetica', 'bold')
  doc.text(COMPANY_NAME, mL, 17); doc.setFont('helvetica', 'normal')
  doc.setFontSize(12); doc.setTextColor(40, 40, 40)
  doc.text(`Reporte de Mantenimiento Preventivo${clientFilter ? ` — ${clientFilter}` : ''}`, mL, 26)
  doc.setFontSize(9); doc.setTextColor(100, 100, 100)
  doc.text(`Generado: ${formatDate(Date.now())}`, mL, 33)

  let y = 42

  // Summary table
  const overdue = filtered.filter(e => e.next_service_due && e.next_service_due < now).length
  const dueSoon = filtered.filter(e => e.next_service_due && e.next_service_due >= now && e.next_service_due - now <= THIRTY).length
  const upToDate = filtered.filter(e => e.next_service_due && e.next_service_due - now > THIRTY).length
  const noSchedule = filtered.filter(e => !e.next_service_due).length

  autoTable(doc, {
    startY: y,
    head: [['Total Equipos', 'Al Día ✓', 'Próximos ⚠', 'Vencidos ✗', 'Sin Programa']],
    body: [[String(filtered.length), String(upToDate), String(dueSoon), String(overdue), String(noSchedule)]],
    headStyles: { fillColor: [0, 130, 130], textColor: [255, 255, 255], fontSize: 9 },
    bodyStyles: { fontSize: 10, fontStyle: 'bold' },
    columnStyles: {
      1: { textColor: [34, 140, 34] as [number,number,number] },
      2: { textColor: [180, 140, 0] as [number,number,number] },
      3: { textColor: [200, 50, 50] as [number,number,number] },
    },
  })
  y = (doc as any).lastAutoTable.finalY + 10

  // Group by client
  const byClient: Record<string, any[]> = {}
  filtered.forEach(eq => {
    const key = eq.client_name || 'Sin cliente'
    if (!byClient[key]) byClient[key] = []
    byClient[key].push(eq)
  })

  for (const [clientName, eqList] of Object.entries(byClient).sort()) {
    if (y > pageH - 60) { doc.addPage(); y = 20 }

    doc.setDrawColor(0, 130, 130); doc.setLineWidth(0.4); doc.line(mL, y, pageW - mR, y); y += 6
    doc.setFontSize(11); doc.setTextColor(0, 100, 130); doc.setFont('helvetica', 'bold')
    doc.text(`👤 ${clientName}`, mL, y); doc.setFont('helvetica', 'normal'); y += 4

    autoTable(doc, {
      startY: y,
      head: [['Equipo', 'Marca/Modelo', 'Serial', 'Frecuencia', 'Último Servicio', 'Próximo Servicio', 'Estado']],
      body: eqList.sort((a, b) => (a.next_service_due || 9e15) - (b.next_service_due || 9e15)).map(eq => {
        const eqLogs = logs.filter((l: any) => l.equipment_id === eq.id).sort((a: any, b: any) => b.date - a.date)
        const lastLog = eqLogs[0]
        return [
          `${eq.equipment_type}${eq.location ? `\n${eq.location}` : ''}`,
          `${eq.brand || '-'} ${eq.model || ''}`.trim() || '-',
          eq.serial_number || '-',
          eq.maintenance_interval_months ? intervalLabel(eq.maintenance_interval_months) : '-',
          lastLog ? formatDateShort(lastLog.date) : 'Nunca',
          eq.next_service_due ? formatDateShort(eq.next_service_due) : '-',
          statusLabel(eq),
        ]
      }),
      headStyles: { fillColor: [50, 80, 110], textColor: [255, 255, 255], fontSize: 7 },
      bodyStyles: { fontSize: 8 },
      columnStyles: {
        0: { cellWidth: 32 },
        1: { cellWidth: 30 },
        2: { cellWidth: 26 },
        3: { cellWidth: 22 },
        4: { cellWidth: 22 },
        5: { cellWidth: 22 },
        6: { cellWidth: 20 },
      },
      didParseCell: (data: any) => {
        if (data.section === 'body' && data.column.index === 6) {
          const eq = eqList[data.row.index]
          const [r, g, b] = statusColor(eq)
          data.cell.styles.textColor = [r, g, b]
          data.cell.styles.fontStyle = 'bold'
        }
      },
    })
    y = (doc as any).lastAutoTable.finalY + 8

    // Maintenance history for this client's equipment
    const clientLogs = logs
      .filter((l: any) => eqList.some(eq => eq.id === l.equipment_id))
      .sort((a: any, b: any) => b.date - a.date)
      .slice(0, 20)

    if (clientLogs.length > 0) {
      if (y > pageH - 40) { doc.addPage(); y = 20 }
      doc.setFontSize(8); doc.setTextColor(80, 80, 80); doc.setFont('helvetica', 'bold')
      doc.text('Historial reciente:', mL + 3, y); doc.setFont('helvetica', 'normal'); y += 3

      autoTable(doc, {
        startY: y,
        head: [['Fecha', 'Equipo', 'Trabajo', 'Técnico', 'Notas']],
        body: clientLogs.map((l: any) => {
          const eq = eqList.find(e => e.id === l.equipment_id)
          const typeLabel: Record<string, string> = {
            cleaning: 'Limpieza', deep_cleaning: 'Limpieza Profunda',
            repair: 'Reparación', inspection: 'Inspección', other: 'Otro'
          }
          return [
            formatDateShort(l.date),
            eq ? `${eq.equipment_type}${eq.notes ? ` (${eq.notes.slice(0, 12)})` : ''}` : `ID:${l.equipment_id}`,
            typeLabel[l.maintenance_type] || l.maintenance_type,
            l.technician || '-',
            (l.notes || '-').slice(0, 35),
          ]
        }),
        headStyles: { fillColor: [80, 80, 80], textColor: [255, 255, 255], fontSize: 7 },
        bodyStyles: { fontSize: 7 },
        margin: { left: mL + 3 },
        columnStyles: {
          0: { cellWidth: 18 },
          1: { cellWidth: 30 },
          2: { cellWidth: 28 },
          3: { cellWidth: 20 },
          4: { cellWidth: 76 },
        },
      })
      y = (doc as any).lastAutoTable.finalY + 10
    }
  }

  addFooter()
  const suffix = clientFilter ? `-${clientFilter.replace(/\s+/g, '_')}` : ''
  doc.save(`Mantenimiento${suffix}-${new Date().toISOString().split('T')[0]}.pdf`)
}

// ============ EMPLOYEE 480.6B REPORT — per employee ============
export function generateEmployeeReport(employee: Employee, payments: EmployeePayment[], yearLabel: string) {
  const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'letter' })
  const fmt = (n: number) => `$${n.toFixed(2).replace(/\B(?=(\d{3})+(?!\d))/g, ',')}`
  const fmtDate = (ts: number) => new Date(ts).toLocaleDateString('es-PR', { year: 'numeric', month: '2-digit', day: '2-digit' })

  const fullName = `${employee.first_name} ${employee.last_name}`
  const retPct = employee.retention_percent ?? 10

  // Header
  doc.setFillColor(0, 100, 120)
  doc.rect(0, 0, 216, 32, 'F')
  doc.setFontSize(16); doc.setFont('helvetica', 'bold'); doc.setTextColor(255, 255, 255)
  doc.text(COMPANY_NAME, 14, 12)
  doc.setFontSize(10); doc.setFont('helvetica', 'normal')
  doc.text(`Reporte de Pagos — Contratista Independiente (480.6B)`, 14, 20)
  doc.text(`Período: ${yearLabel}`, 14, 27)

  // Employee info box
  doc.setFontSize(12); doc.setFont('helvetica', 'bold'); doc.setTextColor(30, 30, 30)
  doc.text(fullName, 14, 44)
  doc.setFontSize(9); doc.setFont('helvetica', 'normal'); doc.setTextColor(80, 80, 80)
  if (employee.phone) doc.text(`Tel: ${employee.phone}`, 14, 51)
  if (employee.email) doc.text(`Email: ${employee.email}`, 14, 57)
  if (employee.specialties) doc.text(`Especialidad: ${employee.specialties}`, 14, 63)
  doc.text(`Tipo: Contratista Independiente — Formulario 480.6B Puerto Rico`, 14, 69)
  doc.text(`Retención: ${retPct}%`, 14, 75)

  // Totals summary
  const totalGross = payments.reduce((s, p) => s + p.amount_gross, 0)
  const totalRetention = payments.reduce((s, p) => s + p.retention_amount, 0)
  const totalNet = payments.reduce((s, p) => s + p.amount_net, 0)
  const totalDays = payments.reduce((s, p) => s + p.days_worked, 0)

  doc.setFillColor(240, 248, 255)
  doc.rect(14, 80, 183, 22, 'F')
  doc.setFontSize(9); doc.setFont('helvetica', 'bold'); doc.setTextColor(0, 80, 100)
  doc.text(`Total Días: ${totalDays}`, 20, 88)
  doc.text(`Total Bruto: ${fmt(totalGross)}`, 70, 88)
  doc.text(`Retención ${retPct}%: ${fmt(totalRetention)}`, 120, 88)
  doc.text(`Total Neto: ${fmt(totalNet)}`, 168, 88)
  doc.setFontSize(8); doc.setFont('helvetica', 'normal'); doc.setTextColor(100, 100, 100)
  doc.text(`${payments.length} pagos registrados`, 20, 96)

  // Payments table
  const sorted = [...payments].sort((a, b) => a.date - b.date)
  const rows = sorted.map(p => [
    fmtDate(p.date),
    p.description,
    String(p.days_worked),
    fmt(p.daily_rate),
    fmt(p.amount_gross),
    fmt(p.retention_amount),
    fmt(p.amount_net),
    p.payment_method || 'Cash',
  ])

  autoTable(doc, {
    startY: 108,
    head: [['Fecha', 'Descripción / Trabajo', 'Días', 'Tarifa/Día', 'Bruto', `Ret. ${retPct}%`, 'Neto', 'Método']],
    body: rows,
    foot: [['', 'TOTALES', String(totalDays), '', fmt(totalGross), fmt(totalRetention), fmt(totalNet), '']],
    headStyles: { fillColor: [0, 100, 120], textColor: [255, 255, 255], fontSize: 8 },
    bodyStyles: { fontSize: 8, textColor: [40, 40, 40] },
    footStyles: { fillColor: [220, 240, 245], fontStyle: 'bold', fontSize: 8 },
    columnStyles: {
      0: { cellWidth: 20 },
      1: { cellWidth: 55 },
      2: { cellWidth: 12, halign: 'center' },
      3: { cellWidth: 20, halign: 'right' },
      4: { cellWidth: 22, halign: 'right' },
      5: { cellWidth: 22, halign: 'right' },
      6: { cellWidth: 22, halign: 'right' },
      7: { cellWidth: 18 },
    },
    alternateRowStyles: { fillColor: [248, 252, 255] },
  })

  // Footer note
  const finalY = (doc as any).lastAutoTable?.finalY || 200
  doc.setFontSize(7); doc.setTextColor(120, 120, 120); doc.setFont('helvetica', 'italic')
  doc.text('Este documento es para fines informativos. La retención se reporta en el Formulario 480.6B del Departamento de Hacienda de Puerto Rico.', 14, finalY + 8)
  doc.text(`Generado: ${new Date().toLocaleDateString('es-PR')}`, 14, finalY + 14)

  doc.save(`Empleado_${fullName.replace(/\s+/g, '_')}_${yearLabel}.pdf`)
}

// ============ ALL EMPLOYEES SUMMARY REPORT ============
export function generateEmployeesAllReport(employees: Employee[], paymentsMap: Record<number, EmployeePayment[]>, yearLabel: string) {
  const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'letter' })
  const fmt = (n: number) => `$${n.toFixed(2).replace(/\B(?=(\d{3})+(?!\d))/g, ',')}`

  // Header
  doc.setFillColor(0, 100, 120)
  doc.rect(0, 0, 216, 32, 'F')
  doc.setFontSize(16); doc.setFont('helvetica', 'bold'); doc.setTextColor(255, 255, 255)
  doc.text(COMPANY_NAME, 14, 12)
  doc.setFontSize(10); doc.setFont('helvetica', 'normal')
  doc.text('Resumen de Nómina — Contratistas Independientes (480.6B)', 14, 20)
  doc.text(`Período: ${yearLabel}`, 14, 27)

  let grandGross = 0, grandRetention = 0, grandNet = 0, grandDays = 0

  const rows = employees.filter(e => e.active).map(emp => {
    const pmts = paymentsMap[emp.id!] || []
    const gross = pmts.reduce((s, p) => s + p.amount_gross, 0)
    const retention = pmts.reduce((s, p) => s + p.retention_amount, 0)
    const net = pmts.reduce((s, p) => s + p.amount_net, 0)
    const days = pmts.reduce((s, p) => s + p.days_worked, 0)
    const retPct = emp.retention_percent ?? 10
    grandGross += gross; grandRetention += retention; grandNet += net; grandDays += days
    return [
      `${emp.first_name} ${emp.last_name}`,
      emp.specialties || '—',
      `${retPct}%`,
      String(days),
      String(pmts.length),
      fmt(gross),
      fmt(retention),
      fmt(net),
    ]
  })

  autoTable(doc, {
    startY: 42,
    head: [['Empleado', 'Especialidad', 'Ret.', 'Días', '# Pagos', 'Total Bruto', 'Total Retenido', 'Total Neto']],
    body: rows,
    foot: [['TOTALES', '', '', String(grandDays), '', fmt(grandGross), fmt(grandRetention), fmt(grandNet)]],
    headStyles: { fillColor: [0, 100, 120], textColor: [255, 255, 255], fontSize: 9 },
    bodyStyles: { fontSize: 9 },
    footStyles: { fillColor: [220, 240, 245], fontStyle: 'bold', fontSize: 9 },
    columnStyles: {
      0: { cellWidth: 42 },
      1: { cellWidth: 35 },
      2: { cellWidth: 12, halign: 'center' },
      3: { cellWidth: 12, halign: 'center' },
      4: { cellWidth: 16, halign: 'center' },
      5: { cellWidth: 25, halign: 'right' },
      6: { cellWidth: 27, halign: 'right' },
      7: { cellWidth: 25, halign: 'right' },
    },
    alternateRowStyles: { fillColor: [248, 252, 255] },
  })

  const finalY = (doc as any).lastAutoTable?.finalY || 120
  doc.setFontSize(7); doc.setTextColor(120, 120, 120); doc.setFont('helvetica', 'italic')
  doc.text('Todos los contratistas deben recibir el Formulario 480.6B antes del 28 de febrero del año siguiente.', 14, finalY + 8)
  doc.text(`Generado: ${new Date().toLocaleDateString('es-PR')}`, 14, finalY + 14)

  doc.save(`Nomina_Todos_${yearLabel}.pdf`)
}

export function exportEventsCSV(
  events: EventRecord[],
  startDate: number,
  endDate: number
) {
  const filtered = events.filter(e => e.timestamp >= startDate && e.timestamp <= endDate).sort((a, b) => a.timestamp - b.timestamp)

  const headers = ['Fecha', 'Tipo', 'Categoría', 'Monto', 'Método de Pago', 'Vendor/Cliente', 'Nota', 'Tipo Gasto', 'Vehículo']
  const rows = filtered.map(e => [
    new Date(e.timestamp).toLocaleDateString('es-PR'),
    e.type === 'income' ? 'Ingreso' : 'Gasto',
    e.category || '',
    e.amount.toFixed(2),
    getPaymentLabel(e.payment_method),
    e.vendor || e.client || '',
    (e.note || '').replace(/,/g, ';').replace(/\n/g, ' '),
    e.expense_type || 'business',
    e.vehicle_id || ''
  ])

  const csv = [headers.join(','), ...rows.map(r => r.join(','))].join('\n')
  const BOM = '\uFEFF'
  const blob = new Blob([BOM + csv], { type: 'text/csv;charset=utf-8;' })
  const url = URL.createObjectURL(blob)
  const a = document.createElement('a')
  a.href = url
  a.download = `Transacciones-${new Date(startDate).toISOString().split('T')[0]}-a-${new Date(endDate).toISOString().split('T')[0]}.csv`
  a.click()
  URL.revokeObjectURL(url)
}

// ============ INVENTORY REPORTS ============

export function generateInventoryReport(items: InventoryItem[]) {
  const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'letter' })
  const pageW = doc.internal.pageSize.getWidth()
  let y = 14

  doc.setFontSize(16).setFont('helvetica', 'bold')
  doc.text('Inventario de Piezas y Materiales', pageW / 2, y, { align: 'center' }); y += 7
  doc.setFontSize(9).setFont('helvetica', 'normal')
  doc.text(`${COMPANY_NAME} · ${new Date().toLocaleDateString('es-PR')}`, pageW / 2, y, { align: 'center' }); y += 8

  const active = items.filter(i => i.active)
  const lowStock = active.filter(i => i.quantity <= i.min_quantity)
  const totalValue = active.reduce((s, i) => s + i.quantity * i.unit_cost, 0)

  // Summary row
  doc.setFontSize(9)
  doc.text(`Total ítems activos: ${active.length}   |   Bajo mínimo: ${lowStock.length}   |   Valor total: $${totalValue.toFixed(2)}`, 14, y); y += 6

  const statusLabel = (q: number, min: number) => q <= min ? '🔴 Crítico' : q <= min * 2 ? '🟡 Bajo' : '🟢 OK'

  autoTable(doc, {
    startY: y,
    head: [['Artículo', 'SKU', 'Categoría', 'Stock', 'Mín', 'Estado', 'Ubicación', 'Costo Unit.', 'Valor']],
    body: active.sort((a, b) => {
      const rank = (i: InventoryItem) => i.quantity <= i.min_quantity ? 0 : i.quantity <= i.min_quantity * 2 ? 1 : 2
      return rank(a) - rank(b) || a.name.localeCompare(b.name)
    }).map(i => [
      i.name,
      i.sku || '',
      i.category,
      `${i.quantity} ${i.unit}`,
      `${i.min_quantity} ${i.unit}`,
      statusLabel(i.quantity, i.min_quantity),
      i.location_detail || i.location,
      `$${i.unit_cost.toFixed(2)}`,
      `$${(i.quantity * i.unit_cost).toFixed(2)}`,
    ]),
    styles: { fontSize: 8, cellPadding: 2 },
    headStyles: { fillColor: [0, 128, 128], textColor: 255 },
    alternateRowStyles: { fillColor: [240, 248, 248] },
    columnStyles: { 3: { halign: 'center' }, 4: { halign: 'center' }, 5: { halign: 'center' }, 7: { halign: 'right' }, 8: { halign: 'right' } },
  })

  const finalY = (doc as any).lastAutoTable.finalY + 6
  doc.setFontSize(8).text(`Valor total del inventario activo: $${totalValue.toFixed(2)}`, pageW - 14, finalY, { align: 'right' })

  doc.save(`Inventario-${new Date().toISOString().split('T')[0]}.pdf`)
}

export function generateBitacoraMonthlyPDF(entries: BitacoraEntry[], monthLabel: string) {
  const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'letter' })
  const pageW = doc.internal.pageSize.getWidth()
  let y = 14

  doc.setFontSize(18).setFont('helvetica', 'bold').setTextColor(0, 150, 150)
  doc.text(COMPANY_NAME, pageW / 2, y, { align: 'center' }); y += 8
  doc.setFontSize(13).setFont('helvetica', 'bold').setTextColor(40, 40, 40)
  doc.text(`Resumen Mensual de Bitácora — ${monthLabel}`, pageW / 2, y, { align: 'center' }); y += 7
  doc.setFontSize(8).setFont('helvetica', 'normal').setTextColor(120, 120, 120)
  doc.text(`Generado: ${new Date().toLocaleDateString('es-PR', { day: '2-digit', month: 'long', year: 'numeric' })}`, pageW / 2, y, { align: 'center' }); y += 8

  // Summary stats
  const sorted = [...entries].sort((a, b) => a.date.localeCompare(b.date))
  const totalDays = sorted.length
  const totalJobs = sorted.reduce((s, e) => s + (e.jobs_count || 0), 0)
  const totalHours = sorted.reduce((s, e) => s + (e.hours_estimated || 0), 0)
  const allClients = [...new Set(sorted.flatMap(e => e.clients_mentioned || []))]
  const allLocations = [...new Set(sorted.flatMap(e => e.locations || []))]
  const emergencies = sorted.filter(e => e.had_emergency).length
  const pending = sorted.filter(e => e.invoice_pending)

  doc.setFontSize(9).setFont('helvetica', 'bold').setTextColor(40, 40, 40)
  doc.text('RESUMEN DEL MES', 14, y); y += 5
  doc.setFont('helvetica', 'normal')

  const stats = [
    [`Días trabajados: ${totalDays}`, `Trabajos realizados: ${totalJobs}`, `Horas estimadas: ${totalHours}h`],
    [`Clientes atendidos: ${allClients.length}`, `Municipios visitados: ${allLocations.length}`, `Emergencias: ${emergencies}`],
    [`Sin factura: ${pending.length}`, '', ''],
  ]
  stats.forEach(row => {
    doc.text(row[0], 14, y)
    if (row[1]) doc.text(row[1], 80, y)
    if (row[2]) doc.text(row[2], 150, y)
    y += 5
  })
  y += 3

  // Daily entries table
  doc.setFontSize(9).setFont('helvetica', 'bold').setTextColor(0, 150, 150)
  doc.text('ENTRADAS DIARIAS', 14, y); y += 3

  autoTable(doc, {
    startY: y,
    head: [['Fecha', 'Clientes', 'Municipio', 'Trabajos', 'Horas', 'Factura', 'Resumen']],
    body: sorted.map(e => [
      new Date(e.date + 'T12:00:00').toLocaleDateString('es-PR', { weekday: 'short', day: '2-digit', month: 'short' }),
      (e.clients_mentioned || []).join(', ') || '—',
      (e.locations || []).join(', ') || '—',
      `${e.jobs_count || 0}`,
      e.hours_estimated ? `${e.hours_estimated}h` : '—',
      e.invoice_pending ? '⚠️ Pendiente' : '✅ OK',
      (e.summary || '').substring(0, 60),
    ]),
    styles: { fontSize: 7, cellPadding: 1.5 },
    headStyles: { fillColor: [0, 150, 150], textColor: 255, fontStyle: 'bold' },
    alternateRowStyles: { fillColor: [240, 250, 250] },
    columnStyles: {
      0: { cellWidth: 22 }, 1: { cellWidth: 35 }, 2: { cellWidth: 25 },
      3: { cellWidth: 12, halign: 'center' }, 4: { cellWidth: 12, halign: 'center' },
      5: { cellWidth: 18, halign: 'center' }, 6: { cellWidth: 60 },
    },
    didParseCell: (data) => {
      if (data.column.index === 5 && data.cell.raw === '⚠️ Pendiente') {
        data.cell.styles.textColor = [180, 90, 0]
        data.cell.styles.fontStyle = 'bold'
      }
    },
  })

  y = (doc as any).lastAutoTable.finalY + 8

  // Pending invoices section
  if (pending.length > 0) {
    if (y > 230) { doc.addPage(); y = 14 }
    doc.setFontSize(9).setFont('helvetica', 'bold').setTextColor(180, 90, 0)
    doc.text('⚠️ TRABAJOS SIN FACTURA', 14, y); y += 3

    autoTable(doc, {
      startY: y,
      head: [['Fecha', 'Clientes', 'Municipio', 'Trabajos', 'Descripción']],
      body: pending.map(e => [
        new Date(e.date + 'T12:00:00').toLocaleDateString('es-PR', { day: '2-digit', month: 'long', year: 'numeric' }),
        (e.clients_mentioned || []).join(', '),
        (e.locations || []).join(', '),
        `${e.jobs_count || 0}`,
        (e.highlights || []).join(' · ').substring(0, 80) || (e.summary || '').substring(0, 80),
      ]),
      styles: { fontSize: 8, cellPadding: 2 },
      headStyles: { fillColor: [180, 90, 0], textColor: 255 },
      alternateRowStyles: { fillColor: [255, 248, 235] },
    })
  }

  // Clients summary
  if (allClients.length > 0) {
    y = (doc as any).lastAutoTable.finalY + 8
    if (y > 230) { doc.addPage(); y = 14 }
    doc.setFontSize(9).setFont('helvetica', 'bold').setTextColor(40, 40, 40)
    doc.text('CLIENTES ATENDIDOS', 14, y); y += 3

    const clientVisits: Record<string, number> = {}
    sorted.forEach(e => (e.clients_mentioned || []).forEach(c => { clientVisits[c] = (clientVisits[c] || 0) + 1 }))

    autoTable(doc, {
      startY: y,
      head: [['Cliente', 'Visitas en el mes']],
      body: Object.entries(clientVisits).sort((a, b) => b[1] - a[1]).map(([c, v]) => [c, `${v} visita${v > 1 ? 's' : ''}`]),
      styles: { fontSize: 8, cellPadding: 2 },
      headStyles: { fillColor: [60, 60, 100], textColor: 255 },
      alternateRowStyles: { fillColor: [245, 245, 255] },
      columnStyles: { 1: { halign: 'center' } },
    })
  }

  doc.save(`Bitacora-${monthLabel.replace(/\s+/g, '-')}.pdf`)
}

export function generateInventoryMovementsReport(
  movements: InventoryMovement[],
  items: InventoryItem[],
  start: number,
  end: number,
  label: string,
) {
  const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'letter' })
  const pageW = doc.internal.pageSize.getWidth()
  let y = 14

  doc.setFontSize(16).setFont('helvetica', 'bold')
  doc.text('Movimientos de Inventario', pageW / 2, y, { align: 'center' }); y += 7
  doc.setFontSize(9).setFont('helvetica', 'normal')
  doc.text(`${COMPANY_NAME} · Período: ${label}`, pageW / 2, y, { align: 'center' }); y += 8

  const totalIn = movements.filter(m => m.type === 'in').reduce((s, m) => s + m.quantity, 0)
  const totalOut = movements.filter(m => m.type === 'out').reduce((s, m) => s + m.quantity, 0)
  const totalCost = movements.filter(m => m.type === 'in').reduce((s, m) => s + (m.total_cost || 0), 0)

  doc.text(`Entradas: ${totalIn} uds   |   Salidas: ${totalOut} uds   |   Costo compras: $${totalCost.toFixed(2)}`, 14, y); y += 6

  const itemMap: Record<number, InventoryItem> = {}
  items.forEach(i => { if (i.id) itemMap[i.id] = i })

  const typeLabel = (t: string) => t === 'in' ? 'Entrada' : t === 'out' ? 'Salida' : 'Ajuste'

  autoTable(doc, {
    startY: y,
    head: [['Fecha', 'Artículo', 'Tipo', 'Cant.', 'Costo Unit.', 'Total', 'Razón', 'Notas']],
    body: movements.map(m => [
      new Date(m.date).toLocaleDateString('es-PR'),
      m.item_name,
      typeLabel(m.type),
      `${m.quantity}`,
      m.unit_cost ? `$${m.unit_cost.toFixed(2)}` : '',
      m.total_cost ? `$${m.total_cost.toFixed(2)}` : '',
      m.reason,
      m.notes || '',
    ]),
    styles: { fontSize: 8, cellPadding: 2 },
    headStyles: { fillColor: [0, 128, 128], textColor: 255 },
    alternateRowStyles: { fillColor: [240, 248, 248] },
    columnStyles: { 3: { halign: 'center' }, 4: { halign: 'right' }, 5: { halign: 'right' } },
  })

  doc.save(`Movimientos-Inventario-${new Date().toISOString().split('T')[0]}.pdf`)
}